"use strict";(self.webpackChunkmy_website=self.webpackChunkmy_website||[]).push([[130],{7735:n=>{n.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"2025-06-02-\uc65c\ucfe0\ubc84\ub124\ud2f0\uc2a4\ub97c \ub3c4\uc785 \ud588\ub294\uac00","metadata":{"permalink":"/blog/2025-06-02-\uc65c\ucfe0\ubc84\ub124\ud2f0\uc2a4\ub97c \ub3c4\uc785 \ud588\ub294\uac00","source":"@site/blog/2025-06-02-\uc65c\ucfe0\ubc84\ub124\ud2f0\uc2a4\ub97c \ub3c4\uc785 \ud588\ub294\uac00.mdx","title":"\uc65c \ucfe0\ubc84\ub124\ud2f0\uc2a4\uc778\uac00?","description":"\uc774 \uae00\uc740 \uc65c?\ub97c \ubb3c\uc5b4\uac00\uba70 \uae30\uc220\uc758 \uae4a\uc740 \uc774\ud574\uc640 \uae30\uc220\uc758 \ud2b8\ub808\uc774\ub4dc \uc624\ud504\ub97c \uace0\ub824\ud558\uace0 \uc124\uacc4\uc790\ub4e4\uc758 \uace0\ubbfc\uc744 \uc5ff\ubcf4\ub294 \ud0d0\uad6c \uacfc\uc815\uc744 \uae30\ub85d\ud569\ub2c8\ub2e4. \ub54c\ub85c\ub294 \uc608\uc0c1\uce58 \ubabb\ud55c \uae38\ub85c \ub4e4\uc5b4\uc11c\uae30\ub3c4 \ud588\uc2b5\ub2c8\ub2e4. \uc774 \uae00\uc744 \ud1b5\ud574 etcd\uc758 \uc804\ubc18\uc801\uc778 \uac1c\ub150\uacfc \uc5b4\ub5bb\uac8c \ub370\uc774\ud130\ub97c \ub3d9\uae30\ud654\ud558\uace0 \uc65c \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294 etcd\ub97c \uc120\ud0dd\ud588\ub294\uc9c0 \ub4f1\uc744 \uc54c\uc544\ubcf4\uace0\uc790 \ud569\ub2c8\ub2e4.","date":"2025-06-02T00:00:00.000Z","tags":[{"inline":false,"label":"Kubernetes","permalink":"/blog/tags/kubernetes","description":"Kubernetes tag description"},{"inline":false,"label":"DevOps","permalink":"/blog/tags/devops","description":"DevOps tag description"}],"readingTime":15.316666666666666,"hasTruncateMarker":true,"authors":[{"name":"Changhwan","title":"\ucee8\ud14c\uc774\ub108\uc640 \ud074\ub77c\uc6b0\ub4dc \ub124\uc774\ud2f0\ube0c \uae30\uc220\uc5d0 \uad00\uc2ec\uc774 \ub9ce\uc73c\uba70, \ud6a8\uc728\uc801\uc774\uba74\uc11c \uc548\uc815\uc801\uc778 \uc11c\ube44\uc2a4\ub97c \ub9cc\ub4e4\uace0\uc790 \ub178\ub825\ud569\ub2c8\ub2e4.","url":"https://github.com/changhwanK","page":null,"imageURL":"/img/insta.jpg","key":"changhwan"}],"frontMatter":{"slug":"2025-06-02-\uc65c\ucfe0\ubc84\ub124\ud2f0\uc2a4\ub97c \ub3c4\uc785 \ud588\ub294\uac00","title":"\uc65c \ucfe0\ubc84\ub124\ud2f0\uc2a4\uc778\uac00?","authors":["changhwan"],"tags":["kubernetes","devops"],"date":"2025-06-02T00:00:00.000Z","comments":true,"toc":true},"unlisted":false,"nextItem":{"title":"Inside etcd - \uc65c K8s\ub294 etcd\ub97c \ubc31\ud0b9 \uc2a4\ud1a0\ub9ac\uc9c0\ub85c \uc120\ud0dd\ud588\uc744\uae4c?","permalink":"/blog/2025-05-21-Inside etcd - \uc65c K8s\ub294 etcd\ub97c \ubc31\ud0b9 \uc2a4\ud1a0\ub9ac\uc9c0\ub85c \uc120\ud0dd\ud588\uc744\uae4c"}},"content":"\uc774 \uae00\uc740 \uc65c?\ub97c \ubb3c\uc5b4\uac00\uba70 \uae30\uc220\uc758 \uae4a\uc740 \uc774\ud574\uc640 \uae30\uc220\uc758 \ud2b8\ub808\uc774\ub4dc \uc624\ud504\ub97c \uace0\ub824\ud558\uace0 \uc124\uacc4\uc790\ub4e4\uc758 \uace0\ubbfc\uc744 \uc5ff\ubcf4\ub294 \ud0d0\uad6c \uacfc\uc815\uc744 \uae30\ub85d\ud569\ub2c8\ub2e4. \ub54c\ub85c\ub294 \uc608\uc0c1\uce58 \ubabb\ud55c \uae38\ub85c \ub4e4\uc5b4\uc11c\uae30\ub3c4 \ud588\uc2b5\ub2c8\ub2e4. \uc774 \uae00\uc744 \ud1b5\ud574 etcd\uc758 \uc804\ubc18\uc801\uc778 \uac1c\ub150\uacfc \uc5b4\ub5bb\uac8c \ub370\uc774\ud130\ub97c \ub3d9\uae30\ud654\ud558\uace0 \uc65c \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294 etcd\ub97c \uc120\ud0dd\ud588\ub294\uc9c0 \ub4f1\uc744 \uc54c\uc544\ubcf4\uace0\uc790 \ud569\ub2c8\ub2e4.\\n\\n\x3c!-- truncate --\x3e\\n\\n\ud68c\uc0ac\uc5d0\uc11c \ucfe0\ubc84\ub124\ud2f0\uc2a4 \uae30\ubc18\uc73c\ub85c \uc11c\ube44\uc2a4\ub97c \uc57d 1\ub144\uc815\ub3c4 \uc6b4\uc601 \uc911\uc778 \uc0c1\ud0dc\uc785\ub2c8\ub2e4. 2024\ub144\uc758 \ube44\uc988\ub2c8\uc2a4 \ubaa9\ud45c\ub294 **\uc6b0\ub9ac Platform\uc744 Boxing\ud558\uc5ec \uace0\uac1d\uc0ac\uc5d0 \ub51c\ub9ac\ubc84\ub9ac \ud558\uace0 \uc6b4\uc601\ud558\ub294 \uac83** \uc774\uc5c8\uc2b5\ub2c8\ub2e4.\\n\\n**\ubaa9\ud45c:**\\n\\n> \uc2e4\uc81c \uace0\uac1d\uc0ac\uc758 \ubcf4\uc548 \uc694\uad6c\uc0ac\ud56d\uc744 \ucda9\uc871 \uc2dc\ud0a4\uba70 **\u201c\uc6b0\ub9ac Platform\uc744 \u2018\uc804\ub2ec\u2019 \ud558\uace0 \u2018\uc6b4\uc601\u2019 \ud574\uc57c \ud55c\ub2e4.\u201d (No Inbound Only OutBound)**\\n>\\n\\n**\ub3cc\uc544\ubcf4\uba74:**\\n\\n\uc774 \ubb38\uc81c\ub97c \ud574\uacb0\ud574\uc57c \ud560 \ub54c\ucbe4\uc778 23\ub144 \ud6c4\ubc18\uae30\uc5d0 \ud300\uc7a5\ub2d8 \uc0c8\ub86d\uac8c \uc624\uc168\uc2b5\ub2c8\ub2e4. \uc0c8\ub85c\uc624\uc2e0 \ud300\uc7a5\ub2d8\uc758 \uc8fc\uc694 \ucee4\ub9ac\uc5b4\ub294 \ud074\ub77c\uc6b0\ub4dc\uc640 \ucfe0\ubc84\ub124\ud2f0\uc2a4\uc600\uace0 \ud300\uc7a5\ub2d8\uc774 \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub97c \uc798 \uc544\uc2e0\ub2e4\ub294 \uc774\uc720\ub85c \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub97c \uc774\uc6a9\ud574 \ud574\uacb0\ud558\uace0\uc790 \ud588\uc2b5\ub2c8\ub2e4. \uacb0\ub860\uc801\uc73c\ub85c \ucd1d 2\uac1c\uc758 \uace0\uac1d\uc0ac\uc5d0 \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub97c \uae30\ubc18\uc758 \ud50c\ub7ab\ud3fc Boxing\ud558\uc5ec \ub51c\ub9ac\ubc84\ub9ac\ud558\uc600\uace0 \ud504\ub85c\uc81d\ud2b8\ub97c \uc131\uacf5\uc801\uc73c\ub85c \uc6b4\uc601\ud558\uc5ec 25\ub144\uc5d0\ub3c4 \ub2e4\ub978 \ud504\ub85c\uc81d\ud2b8\ub4e4\uc744 \ud568\uaed8\ud558\uac8c \ub418\uc5c8\uc2b5\ub2c8\ub2e4.  \\n\\n\ud558\uc9c0\ub9cc \uc774 \uae00\uc758 \ud2b8\ub9ac\uac70 \ub77c\uace0 \ubcfc \uc218 \uc788\ub294\ub370 \uc9c0\uae08 \uc0dd\uac01\ud574\ubcf4\uba74 \uc544\uc26c\uc6b4 \uc810\uc774 \uc874\uc7ac\ud569\ub2c8\ub2e4. **\u201c\uc65c \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub97c \uc0ac\uc6a9\ud588\ub098\uc694?\u201d** \ub77c\uace0 \uc9c8\ubb38\ud55c\ub2e4\uba74 \ub17c\ub9ac\uc801\uc73c\ub85c \ub300\ub2f5\ud558\uae30 \uc5b4\ub835\uace0 \uc2a4\uc2a4\ub85c\ub3c4 \ub0a9\ub4dd\ud558\uae30\ub3c4 \uc5b4\ub835\uc2b5\ub2c8\ub2e4. \ub530\ub77c\uc11c \uc774 \uae00\uc744 \uc791\uc131\ud558\uba70 \uc870\uae08\ub354 \ud559\uc2b5\ud558\uba70 \uc55e\uc73c\ub85c  0 \u2192 1 \uc744 \ub118\uc5b4 1 \u2192 10 \uacbd\ud5d8\uc744 \uc313\uc744 \uc218 \uc788\uac8c \ub178\ub825\ud574\ubcfc \uc608\uc815\uc785\ub2c8\ub2e4.\\n\\n## **\ucfe0\ubc84\ub124\ud2f0\uc2a4\ub780 \ubb34\uc5c7\uc778\uac00?**\\n\\n\uba3c\uc800, \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub780 \ubb34\uc5c7\uc774\uace0 \uc5b4\ub5a4 \ubb38\uc81c\ub97c \ud574\uacb0\ud558\uae30 \uc704\ud574 \ub4f1\uc7a5\ud55c \uae30\uc220\uc778\uc9c0 \uc54c\uc544\ubcf4\uace0\uc790 \ud569\ub2c8\ub2e4.\\n\\n> *Kubernetes is an open-source container orchestration system for automating software deployment, scaling, and management*  \\n> by Wiki\\n\\n\ucfe0\ubc84\ub124\ud2f0\uc2a4\uc5d0 \ub300\ud55c \uc815\uc758\ub97c \uc704\ud0a4 \ubc31\uacfc\uc5d0\uc11c\ub294 ***\u201c\uc18c\ud504\ud2b8\uc6e8\uc5b4\uc758 \uc790\ub3d9\ud654\ub41c \ubc30\ud3ec\uc640 \uc2a4\ucf00\uc77c\ub9c1 \uadf8\ub9ac\uace0 \uc6b4\uc601\uc744 \uc704\ud55c \uc624\ud508 \uc18c\uc2a4 \ucee8\ud14c\uc774\ub108 \uc624\ucf00\uc2a4\ud2b8\ub808\uc774\uc158 \uc2dc\uc2a4\ud15c\uc774\ub77c \uc815\uc758\ud569\ub2c8\ub2e4.\u201d***  \uc989, \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294 \uc790\ub3d9\ud654\ub41c \ucee8\ud14c\uc774\ub108 \uc6b4\uc601 \uad00\ub9ac \ub3c4\uad6c\uc778 \uac83\uc785\ub2c8\ub2e4. **\u2018\uc624\ucf00\uc2a4\ud2b8\ub808\uc774\uc158\u2019** \uc774\ub780 \ud0a4\uc6cc\ub4dc\uac00 \ub4f1\uc7a5\ud558\ub294\ub370 \uadf8\ub807\ub2e4\uba74 \uc624\ucf00\uc2a4\ud2b8\ub808\uc774\uc158\uc774\ub780 \ubb34\uc5c7\uc774\uace0 \ubcf4\ud3b8\uc801\uc778 \uc790\ub3d9\ud654\uc640\ub294 \uc5b4\ub5a4 \ucc28\uc774\uac00 \uc788\uae30\uc5d0 \uc624\ucf00\uc2a4\ud2b8\ub808\uc774\uc158\uc774\ub780 \ub2e8\uc5b4\ub97c \uc0ac\uc6a9\ud560\uae4c\uc694?\\n\\n### **Automation vs Orchestration**\\n\\n**Automation \uc740 \ubb34\uc5b8\uac00\ub97c \uc0c8\ub86d\uac8c \u2018\ubc30\ud3ec\u2019\ud558\uace0 \uba54\ud2b8\ub9ad\uc744 \u2018\uac10\uc9c0\u2019 \ud558\ub294 \uac83\uc5d0 \uc9d1\uc911\ud569\ub2c8\ub2e4.**  \uc989, \uc790\ub3d9\ud654\ub294 \uc190\uc27d\uac8c \ubc30\ud3ec\ud558\uace0 \uc774\uc0c1 \uc9c0\ud45c\ub97c \uc790\ub3d9\uc73c\ub85c \uac10\uc9c0\ud560 \uc218 \uc788\ub294 \uc2dc\uc2a4\ud15c\uc744 \ub9cc\ub4dc\ub294 \uac83\uae4c\uc9c0\uac00 \ubaa9\ud45c\uc785\ub2c8\ub2e4. \ud558\uc9c0\ub9cc \uc6b4\uc601/\uad00\ub9ac\ub97c \uc704\ud574\uc11c\ub294 \ubcf4\ud3b8\uc801\uc778 \uc790\ub3d9\ud654\ub85c\ub294 \ud55c\uacc4\uac00 \uc874\uc7ac\ud558\ub294\ub370 \ubcf4\ud3b8\uc801\uc778 \uc790\ub3d9\ud654\ub9cc\uc73c\ub85c\ub294 \uc774\uc0c1 \uc9c0\ud45c\uac00 \uac10\uc9c0 \ub418\uc5c8\uc744 \ub54c, \uc801\uc808\ud55c \u2018\ud6c4\uc18d \uc870\uce58\u2019\ub97c \uc0ac\ub78c\uc774 \uc9c4\ud589\ud574\uc57c \ud55c\ub2e4\ub294 \ud55c\uacc4\uac00 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n**[\uc218\ub3d9 \uc870\ucde8 \ucf00\uc774\uc2a4]**\\n\\n1. \ucee8\ud14c\uc774\ub108 \ub0b4\ub824\uac04 \uacbd\uc6b0, \uc11c\ubc84\uc5d0 \uc811\uadfc\ud558\uc5ec \ubb38\uc81c \uc788\ub294 \ucee8\ud14c\uc774\ub108\ub97c \uc81c\uac70\ud558\uace0 \ub2e4\uc2dc \ucee8\ud14c\uc774\ub108\ub97c \uc62c\ub824\uc8fc\uc5b4\uc57c \ud55c\ub2e4.\\n2. \ud2b8\ub798\ud53d \uc99d\uac00\ub85c \uc778\ud55c \ubd80\ud558\uac00 \ub298\uc5b4\ub098\ub294 \uacbd\uc6b0, \uc218\ub3d9\uc73c\ub85c \ucee8\ud14c\uc774\ub108 \uc218\ub97c \uc99d\uac00\uc2dc\ud0a8\ub2e4.\\n\\n\uc774\ucc98\ub7fc \uc11c\ube44\uc2a4\ub97c \uc6b4\uc601 \uc2dc \ubb38\uc81c\uac00 \uc0dd\uacbc\uc744 \ub54c \ud6c4\uc18d \uc870\ucde8 \uc791\uc5c5\uc740 \ud544\uc218\uc778\ub370 \uc774\ub7ec\ud55c \uc791\uc5c5\uc774 \u2018\uc0ac\ub78c\u2019\uc5d0 \uc758\uc874\uc801\uc774\ub77c\uba74 \uc2e4\uc218\ud560 \uc5ec\uc9c0\uac00 \uc788\uc73c\uba70 \uc774\ub294 \uace7 \u2018 \uc11c\ube44\uc2a4 \ud488\uc9c8\uc774 \uc0ac\ub78c\uc5d0 \uc758\ud574 \ubc14\ub014 \uc218 \uc788\ub2e4\ub294 \uac83\uc785\ub2c8\ub2e4.\u2019 **\ubcf4\ud3b8\uc801\uc778 \uc790\ub3d9\ud654\ub294 \ud55c\uacc4\uac00 \uc788\uace0 \uc774\ub294 \uc6b0\ub9ac\uac00 \ucd94\uad6c\ud558\ub294 \uc644\ubcbd\ud55c \uc758\ubbf8\uc5d0\uc11c \uc790\ub3d9\ud654\ub294 \uc544\ub2d9\ub2c8\ub2e4. \ub530\ub77c\uc11c O*rchestration*\uc740 \ud6c4\uc18d \uc870\uce58\uc5d0 \ub300\ud55c \uac83\uae4c\uc9c0 \uc790\ub3d9\ud654 \ud574\uc8fc\ub294 \uac83\uc744 \ubaa9\ud45c\ub85c \ub4f1\uc7a5\ud558\uc600\uace0 \ucee8\ud14c\uc774\ub108 \ud658\uacbd\uc5d0\uc11c\ub294 \ud544\uc218\uc801\uc778 \uae30\ub2a5\ub4e4\uc774 \ub418\uc5c8\uc2b5\ub2c8\ub2e4.**\\n\\n\ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294 \uc624\ucf00\uc2a4\ud2b8\ub808\uc774\uc158 \ub3c4\uad6c\ub85c\uc11c \u2018Self Healing\u2019 \uc744 \ud1b5\ud574 \ucee8\ud14c\uc774\ub108\ub97c \uc9c0\uc18d\uc801\uc73c\ub85c \uc815\uc0c1 \uc0c1\ud0dc\ub85c \ubcf5\uad6c\uc2dc\ucf1c\uc8fc\uace0 \ubd80\ud558\uac00 \ub298\uc5b4\ub098 \ucc98\ub9ac\ub7c9\uc774 \ub5a8\uc5b4\uc9c0\uba74, HPA\ub97c \ud1b5\ud574 \u2018Auto Scaling\u2019**\uc744 \uc140\ud504\ub85c** \uc9c4\ud589\ud569\ub2c8\ub2e4. \uc774\ub807\uac8c **\ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294 \uc0ac\ub78c\uc774 \uc9c4\ud589\ud558\ub358 \u2018\ud6c4\uc18d \uc870\ucde8\u2019\ub97c \uc790\uccb4\uc801\uc73c\ub85c \uc81c\uacf5\ud558\uae30 \ub54c\ubb38\uc5d0 \ud734\uba3c \uc5d0\ub7ec\ub85c \uc778\ud55c \ud488\uc9c8\uc774 \uc800\ud558\uac00 \ubc1c\uc0dd\ud558\uc9c0 \uc54a\uc73c\uba70, \ubcf4\ub2e4 \uc644\ubcbd\ud55c \uc790\ub3d9\uc73c\ub85c \uc81c\uacf5\ud558\uae30 \ub54c\ubb38\uc5d0 \uc5d4\uc9c0\ub2c8\uc5b4\uc758 \uc6b4\uc601 \ucf54\uc2a4\ud2b8\ub97c \uc808\uac10 \uc2dc\ucf1c \ub2e4\ub978 \uc0dd\uc0b0\uc801\uc778 \uc791\uc5c5\uc5d0 \ub9ac\uc18c\uc2a4\ub97c \ud22c\uc785\ud560 \uc218 \uc788\uac8c \ud574\uc90d\ub2c8\ub2e4.**\\n\\n### \uadf8 \uc678 \uc5b4\ub5a4 \ub3c4\uad6c\ub4e4\uc774 \uc788\uc744\uae4c?\\n\\n\ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294 \ucee8\ud14c\uc774\ub108\ub97c \uc624\ucf00\uc2a4\ud2b8\ub808\uc774\uc158 \ud558\ub294 \ub3c4\uad6c\uc774\uba70 \uc27d\uac8c \uc0dd\uac01\ud558\uba74 \ucee8\ud14c\uc774\ub108 \uad00\ub9ac \ub3c4\uad6c\uc785\ub2c8\ub2e4. \ub530\ub77c\uc11c \ucee8\ud14c\uc774\ub108 \uad00\ub9ac\ub97c \uc704\ud574 \uaf2d \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub9cc\uc744 \uc0ac\uc6a9\ud574\uc57c \ud558\ub294 \uac83\uc740 \uc544\ub2d9\ub2c8\ub2e4. \uc624\ud788\ub824 \ub2e8\uc21c \ucee8\ud14c\uc774\ub108\ub97c \uad00\ub9ac\ud558\ub294 \uac83\uc774 \ubaa9\uc801\uc774\uba74 \uaf2d \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub97c \uc0ac\uc6a9\ud560 \ud544\uc694\ub294 \uc5c6\uc73c\uba70 \ub300\ud45c\uc801\uc73c\ub85c \uc544\ub798\uc758 \ub300\uc548\ub4e4\uc774 \uc874\uc7ac\ud569\ub2c8\ub2e4.\\n\\n1. Docker Compose\\n2. Docker Swarm\\n3. AWS ECS\\n4. \uc11c\ubc84\ub9ac\uc2a4 \uc11c\ube44\uc2a4\ub4e4\\n\\n\uc774\ub807\uac8c \uac00\uc7a5 \uac04\ub2e8\ud55c Docker Compose \ubd80\ud130 AWS\uc758 ECS \uadf8\ub9ac\uace0 \ub2e4\uc591\ud55c \uc11c\ubc84\ub9ac\uc2a4 \uc81c\ud488\ub4e4\uae4c\uc9c0 \ub300\uc548\uc774 \uc874\uc7ac\ud569\ub2c8\ub2e4. \uc2e4\uc81c\ub85c \uc800\ud76c\ub3c4 Docker Compose\ub9cc\uc73c\ub85c \uac04\ub2e8\ud55c 3tier architecture\ub97c \uc0ac\uc6a9\ud588\uc5c8\uc2b5\ub2c8\ub2e4. \ud558\uc9c0\ub9cc Docker Compose \ub9cc\uc73c\ub85c\ub294 \uc704 \ubb38\uc81c\ub4e4\uc744 \ud574\uacb0\ud560 \uc218 \uc5c6\uc5c8\uace0 \ucee8\ud14c\uc774\ub108 \uae30\ubc18\uc73c\ub85c \uc11c\ube44\uc2a4\ub97c \ub354 \uc798 \uc6b4\uc601\ud558\uae30 \uc704\ud574\uc120 \ucfe0\ubc84\ub124\ud2f0\uc2a4\uac00 \ub9ce\uc740 \ub3c4\uc6c0\uc744 \uc900\ub2e4\uace0 \uc0dd\uac01\ud558\uc5ec \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub97c \ub3c4\uc785\ud558\uc600\uc2b5\ub2c8\ub2e4.\\n\\n\ucd94\uac00\ub85c \ud074\ub77c\uc6b0\ub4dc \ud658\uacbd\uc774\ub77c\uba74 \ucee8\ud14c\uc774\ub108 \uc624\ucf00\uc2a4\ud2b8\ub808\uc774\uc158 \ub3c4\uad6c\ub85c AWS ECS \ub610\ud55c \uac15\ub825\ud569\ub2c8\ub2e4. \ud558\uc9c0\ub9cc ECS\ub294 \uacb0\uad6d AWS \uc758\uc874\uc131\uc774 \ub192\uace0 \uc774\uc2dd\uc131\uc774 \ub5a8\uc5b4\uc9c0\uba70 \ucfe0\ubc84\ub124\ud2f0\uc2a4\uc758 \uc11c\ube44\uc2a4\uc640 \uac19\uc740 \ub85c\ub4dc\ubc38\ub7f0\uc11c\uc758 \ubd80\uc7ac\ub85c \ucee8\ud14c\uc774\ub108 \ub808\ubca8\uc5d0\uc11c \ub85c\ub4dc\ubc38\ub7f0\uc2f1\uacfc \uc11c\ube44\uc2a4 \ub514\uc2a4\ucee4\ubc84\ub9ac \uce21\uba74\uc5d0\uc11c \ud55c\uacc4\uac00 \ub69c\ub837\ud569\ub2c8\ub2e4.\\n\\n---\\n\\n## \uadf8\ub807\ub2e4\uba74 \ubb34\uc5c7\uc774 \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub97c \ud45c\uc900\uc73c\ub85c \ub9cc\ub4e4\uc5c8\uace0 \uc6b0\ub9ac\uac00 \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub97c \uc0ac\uc6a9\ud558\ub294 \uc774\uc720!\\n\\n\ub300\uc548\ub4e4\uc774 \uc874\uc7ac\ud558\uc9c0\ub9cc \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294 \ucee8\ud14c\uc774\ub108 \uc624\ucf00\uc2a4\ud2b8\ub808\uc774\uc158 \ud45c\uc900\uc774\ub418\uc5c8\ub2e4. \ubb34\uc5c7\uc774 \ucee8\ud14c\uc774\ub108 \uc624\ucf00\uc774\uc2a4\ud2b8\ub808\uc774\uc158 \ub3c4\uad6c\uc5d0\uc11c \ud45c\uc900\uc73c\ub85c \uc790\ub9ac \uc7a1\uac8c \ud588\uc744\uae4c\uc694?\\n\\n<img src=\\"/img/kubernetes.png\\" alt=\\"raft.png\\" style={{display: \'block\', marginLeft: \'auto\', marginRight: \'auto\'}} />\\n\\n1. **\ub192\uc740 \uc774\uc2dd\uc131\uacfc \ucfe0\ubc84\ub124\ud2f0\uc2a4 \uc5d0\ucf54\uc2dc\uc2a4\ud15c:**\\n    1. \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub97c \uc0ac\uc6a9\ud558\uba74 \ub2e4\uc591\ud55c \ud074\ub77c\uc6b0\ub4dc \ud658\uacbd \ubc0f \uc628\ud504\ub808\ubbf8\uc2a4 \ud658\uacbd\uc5d0\uc11c\ub3c4 \uc77c\uad00\ub41c \ubc29\uc2dd\uc73c\ub85c \uc560\ud50c\ub9ac\ucf00\uc774\uc158\uc744 \ubc30\ud3ec\ud558\uace0 \uc6b4\uc601\ud560 \uc218 \uc788\uac8c \ud574\uc90d\ub2c8\ub2e4.\\n    2. \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294 CNCF\uc5d0\uc11c \uad00\ub9ac\ud558\ub294 \uc624\ud508\uc18c\uc2a4\uc774\uae30 \ub54c\ubb38\uc5d0 \uae30\ub2a5\ub4e4\uc774 \ube60\ub974\uac8c \ud655\uc7a5\ub418\uace0 \uc788\uc73c\uba70 \ucee4\ubba4\ub2c8\ud2f0\uae30\ubc18\uc758 \uac15\ub825\ud55c \uc5d0\ucf54 \uc2dc\uc2a4\ud15c\uc744 \ud655\ubcf4\ud588\uc2b5\ub2c8\ub2e4. \uc774\ub7ec\ud55c \uc5d0\ucf54 \uc2dc\uc2a4\ud15c\ub4e4\uc740 \uc6b4\uc601\uc5d0 \ub300\ud55c \ucf54\uc2a4\ud2b8\ub97c \ub0ae\ucda5\ub2c8\ub2e4.\\n2. **\ud074\ub7ec\uc2a4\ud130\ub9c1:**\\n    1. \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294 Control Plane, Data Plane\uc73c\ub85c \ud06c\uac8c \ub450 \uac00\uc9c0 \ud074\ub7ec\uc2a4\ud130\ub9c1\uc744 \uc9c0\uc6d0\ud569\ub2c8\ub2e4. \ub530\ub77c\uc11c \ud558\ub098\uc758 \ub178\ub4dc\uac00 Down\ub418\uc5b4\ub3c4 \ub098\uba38\uc9c0 \uc815\uc0c1 \ub178\ub4dc\ub97c \ud65c\uc6a9\ud574 \ube44\uc988\ub2c8\uc2a4\ub97c \uac00\ub3d9\uc2dc\ud0ac \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n3. **\uc720\uc5f0\ud55c \uc2a4\ucf00\uc904\ub9c1:**\\n    1. \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294 \ub2e8\uc21c\ud55c \uc2a4\ucf00\uc904\ub9c1\uc774 \uc544\ub2c8\ub77c Node\uc758 \uc0c1\ud0dc\uc5d0 \ub530\ub77c \ucd5c\uc120\uc758 \uc2a4\ucf00\uc904\ub9c1\uc744 \ud558\uace0\uc790 \ub178\ub825\ud569\ub2c8\ub2e4.\\n    2. \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294 Application\uc758 \ud2b9\uc131\uc744 \uace0\ub824\ud574 \uc720\uc5f0\ud55c \uc2a4\ucf00\uc904\ub9c1\uc744 \uc81c\uacf5\ud569\ub2c8\ub2e4. \uc608\ub97c \ub4e4\uc5b4 AI \uae30\ub2a5\uc774 \ud544\uc694\ud558\ub2e4\uba74 GPU\uac00 \uc124\uce58\ub41c \ub178\ub4dc\uc5d0 \ubc30\uce58\ud558\ub294 \uac83\uc774 \uac00\ub2a5\ud558\uba70, \ud1a0\ud3f4\ub85c\uc9c0\ub97c \uc81c\uacf5\ud574 \ub0b4\uacb0\ud568\uc131\uc744 \ub192\uc77c \uc218 \uc788\uc2b5\ub2c8\ub2e4. \\n4. **\uc190\uc26c\uc6b4 \ub124\ud2b8\uc6cc\ud06c \uad00\ub9ac:**\\n    1. \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294 CNI \ud50c\ub7ec\uadf8\uc778\uc774\ub77c\ub294 \uac00\uc0c1\uc758 \ub124\ud2b8\uc6cc\ud06c\ub97c \ud65c\uc6a9\ud574 \ucee8\ud14c\uc774\ub108\uac04 \ud1b5\uc2e0 \ucee8\ud14c\uc774\ub108\uc5d0 IP \ud560\ub2f9 \ub4f1\ub4f1 \ub2e4\uc591\ud55c \ub124\ud2b8\uc6cc\ud06c \ubb38\uc81c\ub97c \uc678\ubd80 \uc758\uc874\uc131 \uc5c6\uc774 \uc790\uccb4\uc801\uc73c\ub85c \ud574\uacb0\ud560 \uc218 \uc788\uac8c \uc9c0\uc6d0\ud569\ub2c8\ub2e4.\\n5. **\uc11c\ube44\uc2a4 \ub514\uc2a4\ucee4\ubc84\ub9ac\uc640 \ub85c\ub4dc \ubc38\ub7f0\uc2f1:**\\n    1. Pod\ub4e4\uc774 \ub3d9\uc801\uc73c\ub85c \uc0dd\uc131\ub418\uace0 \uc18c\uba78\ub418\uae30 \ub54c\ubb38\uc5d0, \uc11c\ube44\uc2a4 \uac04 \ud1b5\uc2e0\uc744 IP \uae30\ubc18\uc774 \uc544\ub2cc DNS \uae30\ubc18\uc73c\ub85c \ud1b5\uc2e0\ud560 \uc218 \uc788\uac8c \uc9c0\uc6d0\ud569\ub2c8\ub2e4.\\n    2. \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294  \ub85c\ub4dc \ubc38\ub7f0\uc2f1\uc744 \uc774\uc6a9\ud574 Reliability\ub97c \ub192\uc77c \uc218 \uc788\ub294\ub370, Not Ready \uc0c1\ud0dc\uc758 Pod\ub4e4\uc740 \ud2b8\ub798\ud53d\uc5d0\uc11c \uc790\ub3d9\uc73c\ub85c \uc81c\uc678\uc2dc\ucf1c \uace0\uac1d\uc758 \uc2e4\ud328 \uacbd\ud5d8\uc744 \ucd5c\uc18c\ud654 \uc2dc\ud0ac \uc218 \uc788\uc2b5\ub2c8\ub2e4. \\n6. **\uc140\ud504 \ud790\ub9c1\uacfc \uc624\ud1a0\uc2a4\ucf00\uc77c\ub9c1:**\\n    1. \ub0b4\ubd80\uc801\uc73c\ub85c \uc81c\uc5b4\ub8e8\ud504 \uac1c\ub150\uc774 \uc874\uc7ac\ud558\uae30 \ub54c\ubb38\uc5d0 Pod\uac00 \uc8fd\uc5c8\uc744 \ub54c\uc640 \uac19\uc774 Desired State\uc5d0\uc11c \ub2ec\ub77c\uc84c\uc744 \ub54c \uc790\ub3d9\uc73c\ub85c Pod\ub97c \uc0dd\uc131\ud558\ub294 \ub4f1\uc758 **\ud604\uc7ac \uc0c1\ud0dc\uac00 \ubaa9\ud45c \uc0c1\ud0dc\uc640 \uc77c\uce58\ud558\ub3c4\ub85d \uc2dc\uc2a4\ud15c\uc744 \uc870\uc815**\ud558\ub294 \ubc29\uc2dd\uc73c\ub85c \uc791\ub3d9\ud55c\ub2e4.\\n    2. Application\uc758 \ucc98\ub9ac\ub7c9\uc774 \ub5a8\uc5b4\uc838 Latency\uac00 \ub298\uc5b4\ub09c\ub2e4\uba74 HPA, VPA\ub97c \uc0ac\uc6a9\ud574 \ud0c4\ub825\uc801\uc778 \uc2a4\ucf00\uc77c \uc778/\uc544\uc6c3 \uc744 \uc9c0\uc6d0\ud569\ub2c8\ub2e4. \ub098\uc544\uac00 Node\uc758 Resource Pressure\uc5d0\ub3c4 Cluster Autoscaler\ub97c \uc0ac\uc6a9\ud574 \ub178\ub4dc \uc790\uccb4\ub3c4 \ub3d9\uc801\uc73c\ub85c \uc870\uc808\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n7. **\ubcfc\ub968 \uad00\ub9ac:**\\n    1. PV\uc640 PVC\ub97c \ubd84\ub9ac\ud558\uc5ec \uc2a4\ud1a0\ub9ac\uc9c0 \uae30\uc220\uacfc \uc560\ud50c\ub9ac\ucf00\uc774\uc158\uc758 \ucee4\ud50c\ub9c1\uc744 \uc904\uc785\ub2c8\ub2e4. \uc774\ub97c \ud1b5\ud574 \ucee8\ud14c\uc774\ub108\ub294 Row Level\uc758 Storage \uae30\uc220\uc5d0 \uc885\uc18d\uc801\uc774\uc9c0 \uc54a\uace0 PVC \ub9cc\uc744 \uc0ac\uc6a9\ud574 \uc720\uc5f0\ud558\uac8c \ubcfc\ub968\uc744 \uad6c\ucd95\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n    2. \uc774\ub7ec\ud55c \ud2b9\uc9d5\uc740 \uc774\uc2dd\uc131\uc744 \ub192\uc774\uba70, \ube44\uad50\uc801 \ube44\uc6a9\uc774 \ub192\uc740 Raw Level\uc758 \uae30\uc220 \ubcc0\uacbd\uc5d0\ub3c4 \uc548\uc815\uc131\uc744 \uc81c\uacf5\ud569\ub2c8\ub2e4. \\n8. **\ucd5c\uc801\ud654\ub41c GitOps:**\\n    1. \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294 Desired State\ub97c \uc720\uc9c0\ud558\uace0\uc790 \ud569\ub2c8\ub2e4. \ub610 \uc774\ub7ec\ud55c Desired State\ub294 YAML \ud30c\uc77c\uc744 \uc0ac\uc6a9\ud558\uc5ec \uc120\uc5b8\uc801\uc778 \ubc29\uc2dd\uc73c\ub85c \uad00\ub9ac\ub429\ub2c8\ub2e4.\\n    2. \ub530\ub77c\uc11c \ud615\uc0c1 \ucf54\ub4dc\uc758 \ud615\ud0dc\ub85c (IaC) Git\uc744 **Source of Truth\ub85c** \uc774\uc6a9\ud574 \uad00\ub9ac\ud558\uba70 \uc190\uc26c\uc6b4 \ub864\ubc31\uacfc \ud788\uc2a4\ud1a0\ub9ac \ucd94\uc801\uc744 \uc9c0\uc6d0\ud558\uc5ec \uc2e0\ub8b0\uc131\uc744 \ub192\uc77c \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uc774\ub7ec\ud55c \ub9e4\ucee4\ub2c8\uc998\ub4e4\uc740 \uacb0\uad6d \ucee8\ud14c\uc774\ub108 \ud658\uacbd\uc5d0\uc11c \uc11c\ube44\uc2a4\ub97c \uc6b4\uc601\ud560 \ub54c \uace0\ubbfc\ud574\uc57c\ud558\ub294 \uac83\ub4e4\uc785\ub2c8\ub2e4. \uc774\ub7ec\ud55c \uace0\ubbfc\ub4e4\uc5d0 \ub300\ud55c \ud574\ub2f5\uc744 \ucfe0\ubc84\ub124\ud2f0\uc2a4\uac00 \uac00\uc7a5 \uc798 \uc9c0\uc6d0\ud558\uae30 \ub54c\ubb38\uc5d0 \ucfe0\ubc84\ub124\ud2f0\uc2a4\uac00 \ud575\uc2ec\uc774\uc790 \ud45c\uc900\uc774 \ub418\uc5c8\ub2e4 \uc0dd\uac01\ud569\ub2c8\ub2e4.\\n\\n---\\n\\n## \ub2e4\uc2dc \uc0dd\uac01\ud574\ubcf4\ub294,  \u2018\uc6b0\ub9ac\ub294 \uc65c \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub97c \uc120\ud0dd\ud588\ub098\u2019\\n\\n\uc704\uc5d0\uc11c \ucfe0\ubc84\ub124\ud2f0\uc2a4\uac00 \ubb34\uc5c7\uc774\uace0 \uc65c \ud45c\uc900\uc774 \ub418\uc5c8\ub294\uc9c0 \ucfe0\ubc84\ub124\ud2f0\uc2a4\uc758 \uac15\uc810\ub4e4\uc744 \uc815\ub9ac\ud588\uc2b5\ub2c8\ub2e4. \ubb3c\ub860 \ucfe0\ubc84\ub124\ud2f0\uc2a4\uac00 \u2018\uc2e4\ubc84 \ubd88\ub9bf\u2019\uc740 \uc544\ub2c8\uae30 \ub54c\ubb38\uc5d0 \ud2b8\ub808\uc774\ub4dc \uc624\ud504\uac00 \ubc1c\uc0dd\ud558\uc9c0\ub9cc, \uc9c0\uae08 \ub2e4\uc2dc \uc758\uc0ac\uacb0\uc815\uc744 \ud558\ub77c\uace0 \ud574\ub3c4 \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub97c \uc120\ud0dd\ud560 \uac83 \uac19\uc2b5\ub2c8\ub2e4. \uadf8\ub807\ub2e4\uba74 \uc65c \uadf8\ub7f0 \uc120\ud0dd\uc744 \ud560\uc9c0 \ud55c \ubc88 \uc815\ub9ac\ud574\ubcf4\uaca0\uc2b5\ub2c8\ub2e4.\\n\\n\ub9cc\uc57d, \uc9c0\uae08 \ub2e4\uc2dc \uc758\uc0ac\uacb0\uc815\uc744 \ud574\uc57c \ud55c\ub2e4\uba74 Docker Swarm\uacfc \ube44\uad50\ud574\ubcfc \uc218 \uc788\uc744 \uac83 \uac19\uc2b5\ub2c8\ub2e4. Docker Swarm\uc740 Docker engine\uc5d0 \ub0b4\uc7a5\ub418\uc5b4\uc788\ub294 Cluster management, Orchestration Tool\uc774\uba70 Kubernetes \ucc98\ub7fc \ud074\ub7ec\uc2a4\ud130\ub9c1\uc744 \uc9c0\uc6d0\ud558\uba70 \uc5b4\ub290\uc815\ub3c4\uc758 \uc140\ud504 \ud790\ub9c1\ub3c4 \uc9c0\uc6d0\ud569\ub2c8\ub2e4. \ud558\uc9c0\ub9cc \ub3c4\ucee4\uc2a4\uc6dc\uc740 \uc18c\uaddc\ubaa8 \uc11c\ube44\uc2a4\uc5d0 \uc801\ud569\ud558\ub2e4 \ub77c\ub294 \ub0b4\uc6a9\uc744 \uc27d\uac8c \ubcfc \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uc65c \uadf8\ub7f4\uae4c\uc694?\\n\\n### **[\ub3c4\ucee4 \uc2a4\uc6dc\uc758 \ud55c\uacc4\uc810]**\\n\\n1. **\uc11c\ube44\uc2a4 \uc2e0\ub8b0\uc131\uc744 \ubcf4\uc7a5\ud558\uae30\uc5d4 \ubd80\uc871\ud55c \uae30\ub2a5\ub4e4:** \uc11c\ube44\uc2a4\uc758 \uc2e0\ub8b0\uc131\uc744 \uc704\ud574\uc120 **\u2018\uace0\uac00\uc6a9\uc131\u2019** \uacfc **\u2018\ud655\uc7a5\uc131\u2019**\uc774 \uc911\uc694\ud55c \ud3ec\uc778\ud2b8\uc785\ub2c8\ub2e4. \ub3c4\ucee4 \uc2a4\uc6dc\uc740 \ucee8\ud14c\uc774\ub108 \ub808\ubca8\uc5d0\uc11c\uc758 \ubcf5\uad6c\ub97c \uc9c0\uc6d0\ud558\uc9c0\ub9cc \ub9ce\uc774 \ubd80\uc871\ud569\ub2c8\ub2e4. (PDB\ub3c4 \uc5c6\uc74c)\\n\ubb34\uc5c7\ubcf4\ub2e4 \ucee8\ud14c\uc774\ub108\uc5d0 \ub300\ud55c `Health Check`, `Readiness` \uae30\ub2a5\uc774 \uc5c6\uae30 \ub54c\ubb38\uc5d0 \uac89\uc73c\ub85c\ub294 \ubb38\uc81c\uac00 \uc5c6\uc9c0\ub9cc \ub0b4\ubd80\uc871\uc73c\ub85c \ucee8\ud14c\uc774\ub108\uac00 \ube44\uc815\uc0c1\uc801\uc73c\ub85c \ub3d9\uc791\ud558\uace0 \uc788\uc744 \ub54c, \ud2b8\ub798\ud53d\uc774 \ubb38\uc81c\uc758 \ucee8\ud14c\uc774\ub108\uc5d0\ub3c4 \uc804\ub2ec\ub418\uae30 \ub54c\ubb38\uc5d0 \ud2b8\ub798\ud53d\uc774 \uc9c0\uc18d\uc801\uc73c\ub85c \uc2e4\ud328\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \ubc18\uba74, K8s\ub294 \uc790\ub3d9\uc73c\ub85c \ube44\uc815\uc0c1 \ud30c\ub4dc\ub97c \ud2b8\ub798\ud53d \ub300\uc0c1\uc5d0\uc11c \uc9c0\uc6cc \uc2e4\ud328 \uacbd\ud5d8\uc744 \ucd5c\uc18c\ud654 \ud569\ub2c8\ub2e4. \\n\\n    \ub610, \ub178\ub4dc \ub808\ubca8\uc5d0\uc11c \uc7a5\uc560\uac00 \ub0ac\uc744 \ub54c \uc870\ucde8\ud558\ub294 \uac83\uc774 \ubd80\uc871\ud569\ub2c8\ub2e4. \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294 `Unready` \uc0c1\ud0dc\uc758 \ub178\ub4dc\uac00 \ubc1c\uacac\ub418\uba74 \uc989\uc2dc,  \uc815\uc0c1\uc801\uc778 \uc0c1\ud0dc\uc758 \ub178\ub4dc\ub85c \ud30c\ub4dc\uc758 \uc2a4\ucf00\uc904\ub9c1\uc744 \ub2e4\uc2dc\ud569\ub2c8\ub2e4. \uc774\ub807\uac8c K8s\ub294 \uc2e0\ub8b0\uc131\uc744 \ub192\uc77c \uc218 \uc788\ub294 \uc5ec\ub7ec\uac00\uc9c0 \uc790\ub3d9\ud654 \ub9e4\ucee4\ub2c8\uc998\uc774 \uc874\uc7ac\ud558\uc9c0\ub9cc \ub3c4\ucee4 \uc2a4\uc6dc\uc740 \ubd80\uc871\ud569\ub2c8\ub2e4.\\n\\n2. **\ubd80\uc871\ud55c \ub9ac\uc18c\uc2a4 \ud0c0\uc785:** `StatefulSet`**,** `DaemonSet`, `Job` \ub4f1\ub4f1 \ucfe0\ubc84\ub124\ud2f0\uc2a4\uc5d0\ub294 \ub2e8\uc21c \ucee8\ud14c\uc774\ub108\ub97c \ub118\uc5b4 \ucee8\ud14c\uc774\ub108\ub97c \ud65c\uc6a9\ud574 \ubcf4\ub2e4 \ub2e4\uc591\ud55c \uc885\ub958\uc758 \uc11c\ube44\uc2a4\ub97c \uc6b4\uc601\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \ucee8\ud14c\uc774\ub108\ub294 Stateless \ud558\ub2e4\ub294 \ud2b9\uc9d5\uc774 \uc788\ub294\ub370 \uc774\ub294 \ud070 \uc7a5\uc810\uc774\uc9c0\ub9cc \ub2e8\uc810\uc774 \ub420 \ub54c\ub3c4 \uc788\uc2b5\ub2c8\ub2e4. \\n    \\n    \uc608\ub97c \ub4e4\uc5b4 DB \uac19\uc740 \uc11c\ube44\uc2a4\ub294 Stateful \ud574\uc57c \ud558\uba70 Stateful\ud55c \ub9ac\uc18c\uc2a4\ub4e4\uc758 \uace0\uc720\uc131\uc744 \ubcf4\uc7a5\ud558\uace0 \uba87\ubc88\uc744 \uc2a4\ucf00\uc904\ub9c1\ud574\ub3c4 \ub3d9\uc77c\ud55c \ub178\ub4dc\uc5d0 \uc2a4\ucf00\uc904\ub9c1 \ud574\uc90d\ub2c8\ub2e4. \ud558\uc9c0\ub9cc \ub3c4\ucee4 \uc2a4\uc6dc\uc740 \uc774\ub7ec\ud55c \uae30\ub2a5\ub4e4\uc774 \uc874\uc7ac\ud558\uc9c0 \uc54a\uc544 \uc560\ud50c\ub9ac\ucf00\uc774\uc158 \uc131\uaca9\uc5d0 \ub530\ub77c \uc720\uc5f0\ud55c \ub300\ucc98\uac00 \ubd88\uac00\ub2a5\ud569\ub2c8\ub2e4.\\n\\n3. **\ubd80\uc871\ud55c \ubc30\ud3ec \uc2dc\uc2a4\ud15c:** Kubernetes\uc5d0\ub294 `Deployment` \ub97c \uc774\uc6a9\ud574 `RollingUpdate`\ub97c  \uae30\ubcf8\uc801\uc73c\ub85c \uc9c0\uc6d0\ud569\ub2c8\ub2e4. Docker Swarm\ub3c4 service update\ub85c \uac00\ub2a5\ud558\uc9c0\ub9cc \uc138\ubc00\ud55c \uc81c\uc5b4\uac00 \ubd80\uc871\ud569\ub2c8\ub2e4. \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294 graceful down\uc744 \uc9c0\uc6d0\ud560 \uc218 \uc788\uc73c\uba70, `maxUnavailable` \ub97c \ud1b5\ud574 \ucd5c\uc18c\ub85c \uc720\uc9c0\ud560 \ud30c\ub4dc\ub97c \uc120\uc5b8\ud574, \uc11c\ube44\uc2a4\uc758 \uc21c\ub2e8\uc744 \ubc29\uc9c0\ud569\ub2c8\ub2e4. \\n4. **\uc2a4\ucf00\uc904\ub9c1 \uc720\uc5f0\ub3c4\uac00 \ub5a8\uc5b4\uc9c4\ub2e4:** \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294 \uc5b4\ud53c\ub2c8\ud2f0\ub97c \ud1b5\ud574 \uc120\ud638\ud558\ub294 \uacf3\uc73c\ub85c \ucee8\ud14c\uc774\ub108\ub97c \uc2a4\ucf00\uc904\ub9c1\ud560 \uc218 \uc788\uac8c \ub3c4\uc6b0\uba70 \ud1a0\ud3f4\ub85c\uc9c0\ub97c \uc9c0\uc6d0\ud574 \ubd84\uc0b0 \ubc30\uce58\ub97c \uc9c0\uc6d0 \ud558\uc9c0\ub9cc \ub3c4\ucee4 \uc2a4\uc6dc\uc5d0\ub294 \uc774\ub7ec\ud55c \uae30\ub2a5\uc774 \uc5c6\uc2b5\ub2c8\ub2e4. \ub098\uc544\uac00 Resource\uc5d0 \ub300\ud55c Request\uac00 \uc5c6\uc5b4 \ucd5c\uc18c\ud55c\uc758 \uc790\uc6d0\uc744 \ubcf4\uc7a5\ubc1b\ub294 \uac83\ub3c4 \uc5b4\ub835\uc2b5\ub2c8\ub2e4.\\n\\n    \uadf8 \uc678 Node\uac00 Pressure\ub97c \ubc1b\uc744 \uacbd\uc6b0, Evict \ub418\uc5b4\uc57c\ud560 \ud544\uc694\uac00 \uc788\ub294\ub370 \uc774 \uacbd\uc6b0, QoS \ud074\ub798\uc2a4\ub77c\ub294 \uac1c\ub150\uc744 \uc774\uc6a9\ud574 Evict \uc6b0\uc120 \uc21c\uc704\ub97c \uacb0\uc815\ud558\uc5ec \uc8fc\uc694 \uc11c\ube44\uc2a4\uc758 \ucef4\ud4e8\ud305 \ub9ac\uc18c\uc2a4\ub97c \ucd5c\ub300\ud55c \uc548\uc804\ud558\uac8c \uc9c0\ud0ac \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uc774\ub807\uac8c \ub3c4\ucee4 \uc2a4\uc6dc\uc740 \ub9ce\uc740 \ubd80\ubd84\uc5d0\uc11c \uc624\ucf00\uc2a4\ud2b8\ub808\uc774\uc158 \ub3c4\uad6c\uc758 \ud45c\uc900\uc774 \ub418\uae30 \uc5b4\ub824\uc6b4 \ud615\ud0dc\uc785\ub2c8\ub2e4. \uc774\ub7ec\ud55c \ubd80\uc871\ud568\uc740 \uace0\uac1d\uc0ac\uc758 \ud3d0\uc1c4\ub9dd\uc5d0 \uc11c\ube44\uc2a4\ub97c \uc804\ub2ec\ud558\uace0 \uc6b4\uc601\ud558\ub294\ub370 \uc788\uc5b4 \uc2e0\ub8b0\ub3c4\ub97c \uac16\ucd94\uae30 \uc5b4\ub835\ub2e4. \ud310\ub2e8\ub429\ub2c8\ub2e4. \ub530\ub77c\uc11c \uc9c0\uae08\uc5d0\uc11c \uc758\uc0ac\uacb0\uc815\uc744 \ud574\ub3c4 \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub97c \uc120\ud0dd\ud560 \uac83 \uac19\uc2b5\ub2c8\ub2e4.\\n\\n---\\n\\n## \uc5b4\ub5a4 \ud2b8\ub808\uc774\ub4dc \uc624\ud504\ub97c \uac00\uc838\uc57c\ud560\uae4c? - \uc55e\uc73c\ub85c\uc758 \uc219\uc81c\\n\\n\uc9c0\uae08\uae4c\uc9c0 \ucfe0\ubc84\ub124\ud2f0\uc5d0 \ub300\ud574 \uc815\ub9ac\ud558\uace0 \ub3c4\ucee4 \uc2a4\uc6dc\uacfc \ube44\uad50\ud558\uba70 \ucfe0\ubc84\ub124\ud2f0\uc2a4 \ub77c\ub294 \uc758\uc0ac\uacb0\uc815 \ubc30\uacbd\uc744 \uace0\ubbfc\ud574\ubd24\uc2b5\ub2c8\ub2e4. \uc544\uc2dc\uaca0\uc9c0\ub9cc \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub97c \ub3c4\uc785\ud588\ub2e4\uace0 \ub05d\uc774 \uc544\ub2d9\ub2c8\ub2e4. \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294 \ubcf5\uc7a1\ub3c4\uac00 \ub192\uc73c\uba70 \ud2b9\ud788\ub098 EKS\ucc98\ub7fc Managed\uac00 \uc544\ub2c8\uae30 \ub54c\ubb38\uc5d0 \ub9ce\uc740 \ubd80\ubd84\uc744 \uc2e0\uacbd\uc368\uc57c\ub9cc \ubcf4\ub2e4 \uc548\uc815\uc801\uc778 \uc6b4\uc601\uc774 \uac00\ub2a5\ud574\uc9d1\ub2c8\ub2e4.\\n\\n1. **\uac00\uc2dc\uc131\uc744 \ub192\uc5ec\uc57c\ud569\ub2c8\ub2e4.**\\n    1. \ube44\uc988\ub2c8\uc2a4\ub97c \ub2f4\ub2f9\ud558\ub294 \uc560\ud50c\ub9ac\ucf00\uc774\uc158\uc758 \uac00\uc2dc\uc131, \ud074\ub7ec\uc2a4\ud130 \uc6b4\uc601\uc758 Core\uc778 `Control Plane` \uc5d0 \ub300\ud55c \uac00\uc2dc\uc131 \ubaa8\ub450 \ucc59\uaca8\uc57c\ud569\ub2c8\ub2e4. \uad00\ub9ac\ud558\ub294 Workload\ub4e4\uc774 \ub298\uc5b4\ub0a0 \uc218\ub85d `Control Plane` \uc758 \ubd80\ud558\ub294 \ub192\uc544\uc9c0\uace0 Control Plane\uc774 \uc8fd\uc73c\uba74 \uc804\uccb4 \uc7a5\uc560\ub85c \uc774\uc5b4\uc9d1\ub2c8\ub2e4.\\n2. **\ubb3c\ub9ac \uba38\uc2e0 \ub808\ubca8\uc5d0\uc11c\ub3c4 \ucd5c\ub300\ud55c \ubb34\uc911\ub2e8\ub97c \uc9c0\uc6d0\ud574\uc57c \ud569\ub2c8\ub2e4.**\\n    1. \ucfe0\ubc84\ub124\ud2f0\uc2a4 \ubc84\uc804 \uc5c5, \ub178\ub4dc\uc758 \uc7a5\uc560\ub85c \uc778\ud55c \uad50\uccb4 \uacfc\uc815\uc5d0\uc11c \ube44\uc988\ub2c8\uc2a4\ub294 \uc790\uccb4\uac00 \uc644\uc804\ud788 \uba48\ucd94\ub294 \uac83\uc744 \ud53c\ud558\uace0\uc790 \ucd5c\ub300\ud55c \ubb34\uc911\ub2e8\uc744 \uc9c0\uc6d0\ud560 \uc218 \uc788\uc5b4\uc57c \ud569\ub2c8\ub2e4.\\n    2. \uc774\ub97c \ud1b5\ud574 \ud074\ub7ec\uc2a4\ud130\uc5d0 \ub300\ud55c MTTR\ub97c \ub192\uc774\uace0 SLA\ub97c \uc900\uc218\ud560 \uc218 \uc788\uac8c \ub178\ub825\ud574\uc57c \ud569\ub2c8\ub2e4.\\n\\n---\\n\\n## \ub9c8\ubb34\ub9ac\\n\\n\uc9c0\uae08\uae4c\uc9c0 \uba38\ub9ac\uc18d\uc5d0 \ub4a4\uc8fd\ubc15\uc8fd\uc73c\ub85c \uc788\ub358 \uac83\ub4e4\uc744 \uc815\ub9ac\ud574\ubd24\uc2b5\ub2c8\ub2e4. \uc774 \uacfc\uc815\uc5d0\uc11c \ucc98\uc74c \ubaa9\ud45c \ud588\ub358 Why\uc5d0 \ub300\ud55c \ub2f5\ubcc0\ub3c4 \uc0dd\uae34 \uac83 \uac19\uc2b5\ub2c8\ub2e4. \ud2b9\ud788, \ub3c4\ucee4 \uc2a4\uc6dc\uc758 \ud55c\uacc4\uc810\uc744 \uba85\ud655\ud788 \uc774\ud574\ud558\uace0 \uc6b0\ub9ac\uac00 \uc65c \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub97c \uc120\ud0dd\ud574\uc57c \ud588\ub294\uc9c0 \ubcf4\ub2e4 \uba85\ud655\ud574\uc9c4 \uc2dc\uac04\uc774\uc5c8\ub358 \uac83 \uac19\uc2b5\ub2c8\ub2e4. \\n\\n\uc55e\uc73c\ub85c\ub294 \ucfe0\ubc84\ub124\ud2f0\uc2a4 \ud074\ub7ec\uc2a4\ud130 \uad6c\ucd95\uc758 \ubaa8\ubc94 \uc0ac\ub840\ub3c4 \ud559\uc2b5\ud558\uba70 \uc6b0\ub9ac\uc758 \uc57d\uc810\ub4e4\uc744 \uc5b4\ub5bb\uac8c \ubcf4\uc644\ud560 \uc218 \uc788\uc744\uc9c0 \uace0\ubbfc\ud574\ubcf4\ub3c4\ub85d \ud560 \uc608\uc815\uc785\ub2c8\ub2e4."},{"id":"2025-05-21-Inside etcd - \uc65c K8s\ub294 etcd\ub97c \ubc31\ud0b9 \uc2a4\ud1a0\ub9ac\uc9c0\ub85c \uc120\ud0dd\ud588\uc744\uae4c","metadata":{"permalink":"/blog/2025-05-21-Inside etcd - \uc65c K8s\ub294 etcd\ub97c \ubc31\ud0b9 \uc2a4\ud1a0\ub9ac\uc9c0\ub85c \uc120\ud0dd\ud588\uc744\uae4c","source":"@site/blog/2025-05-21-Inside etcd - \uc65c K8s\ub294 etcd\ub97c \ubc31\ud0b9 \uc2a4\ud1a0\ub9ac\uc9c0\ub85c \uc120\ud0dd\ud588\uc744\uae4c.mdx","title":"Inside etcd - \uc65c K8s\ub294 etcd\ub97c \ubc31\ud0b9 \uc2a4\ud1a0\ub9ac\uc9c0\ub85c \uc120\ud0dd\ud588\uc744\uae4c?","description":"\uc774 \uae00\uc740 \uc65c?\ub97c \ubb3c\uc5b4\uac00\uba70 \uae30\uc220\uc758 \uae4a\uc740 \uc774\ud574\uc640 \uae30\uc220\uc758 \ud2b8\ub808\uc774\ub4dc \uc624\ud504\ub97c \uace0\ub824\ud558\uace0 \uc124\uacc4\uc790\ub4e4\uc758 \uace0\ubbfc\uc744 \uc5ff\ubcf4\ub294 \ud0d0\uad6c \uacfc\uc815\uc744 \uae30\ub85d\ud569\ub2c8\ub2e4. \ub54c\ub85c\ub294 \uc608\uc0c1\uce58 \ubabb\ud55c \uae38\ub85c \ub4e4\uc5b4\uc11c\uae30\ub3c4 \ud588\uc2b5\ub2c8\ub2e4. \uc774 \uae00\uc744 \ud1b5\ud574 etcd\uc758 \uc804\ubc18\uc801\uc778 \uac1c\ub150\uacfc \uc5b4\ub5bb\uac8c \ub370\uc774\ud130\ub97c \ub3d9\uae30\ud654\ud558\uace0 \uc65c \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294 etcd\ub97c \uc120\ud0dd\ud588\ub294\uc9c0 \ub4f1\uc744 \uc54c\uc544\ubcf4\uace0\uc790 \ud569\ub2c8\ub2e4.","date":"2025-05-21T00:00:00.000Z","tags":[{"inline":false,"label":"Kubernetes","permalink":"/blog/tags/kubernetes","description":"Kubernetes tag description"}],"readingTime":20.25,"hasTruncateMarker":true,"authors":[{"name":"Changhwan","title":"\ucee8\ud14c\uc774\ub108\uc640 \ud074\ub77c\uc6b0\ub4dc \ub124\uc774\ud2f0\ube0c \uae30\uc220\uc5d0 \uad00\uc2ec\uc774 \ub9ce\uc73c\uba70, \ud6a8\uc728\uc801\uc774\uba74\uc11c \uc548\uc815\uc801\uc778 \uc11c\ube44\uc2a4\ub97c \ub9cc\ub4e4\uace0\uc790 \ub178\ub825\ud569\ub2c8\ub2e4.","url":"https://github.com/changhwanK","page":null,"imageURL":"/img/insta.jpg","key":"changhwan"}],"frontMatter":{"slug":"2025-05-21-Inside etcd - \uc65c K8s\ub294 etcd\ub97c \ubc31\ud0b9 \uc2a4\ud1a0\ub9ac\uc9c0\ub85c \uc120\ud0dd\ud588\uc744\uae4c","title":"Inside etcd - \uc65c K8s\ub294 etcd\ub97c \ubc31\ud0b9 \uc2a4\ud1a0\ub9ac\uc9c0\ub85c \uc120\ud0dd\ud588\uc744\uae4c?","authors":["changhwan"],"tags":["kubernetes"],"comments":true,"toc":true},"unlisted":false,"prevItem":{"title":"\uc65c \ucfe0\ubc84\ub124\ud2f0\uc2a4\uc778\uac00?","permalink":"/blog/2025-06-02-\uc65c\ucfe0\ubc84\ub124\ud2f0\uc2a4\ub97c \ub3c4\uc785 \ud588\ub294\uac00"},"nextItem":{"title":"\ucfe0\ubc84\ub124\ud2f0\uc2a4\uc5d0\uc11c \uc548\uc815\uc801\uc778 \uc11c\ube44\uc2a4 \uc6b4\uc601\uc744 \uc704\ud55c 3\uac00\uc9c0 \uaddc\uce59","permalink":"/blog/\ucfe0\ubc84\ub124\ud2f0\uc2a4\uc5d0\uc11c \uc548\uc815\uc801\uc778 \uc11c\ube44\uc2a4 \uc6b4\uc601\uc744 \uc704\ud55c 3\uac00\uc9c0 \uaddc\uce59\ub4e4"}},"content":"\uc774 \uae00\uc740 \uc65c?\ub97c \ubb3c\uc5b4\uac00\uba70 \uae30\uc220\uc758 \uae4a\uc740 \uc774\ud574\uc640 \uae30\uc220\uc758 \ud2b8\ub808\uc774\ub4dc \uc624\ud504\ub97c \uace0\ub824\ud558\uace0 \uc124\uacc4\uc790\ub4e4\uc758 \uace0\ubbfc\uc744 \uc5ff\ubcf4\ub294 \ud0d0\uad6c \uacfc\uc815\uc744 \uae30\ub85d\ud569\ub2c8\ub2e4. \ub54c\ub85c\ub294 \uc608\uc0c1\uce58 \ubabb\ud55c \uae38\ub85c \ub4e4\uc5b4\uc11c\uae30\ub3c4 \ud588\uc2b5\ub2c8\ub2e4. \uc774 \uae00\uc744 \ud1b5\ud574 etcd\uc758 \uc804\ubc18\uc801\uc778 \uac1c\ub150\uacfc \uc5b4\ub5bb\uac8c \ub370\uc774\ud130\ub97c \ub3d9\uae30\ud654\ud558\uace0 \uc65c \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294 etcd\ub97c \uc120\ud0dd\ud588\ub294\uc9c0 \ub4f1\uc744 \uc54c\uc544\ubcf4\uace0\uc790 \ud569\ub2c8\ub2e4.\\n\\n\x3c!-- truncate --\x3e\\n\\n## etcd [etsy d]\ub780\\n\\n<img src=\\"/img/etcd.png\\" alt=\\"etcd.png\\" style={{display: \'block\', marginLeft: \'auto\', marginRight: \'auto\'}} />\\n\\n[etcd](https://etcd.io/)(etsy d\ub77c \ubd80\ub974\ub354\ub77c)\ub294 \ubd84\uc0b0 \uc2dc\uc2a4\ud15c\uc5d0\uc11c **\u2018\uc124\uc815 \uc815\ubcf4\u2019, \u2018\uc0c1\ud0dc \ub370\uc774\ud130\u2019 \ub4f1\uc744 \uc548\uc815\uc801\uc73c\ub85c \uc800\uc7a5\ud558\uace0 \uad00\ub9ac\ud558\uae30 \uc704\ud55c \ubd84\uc0b0\ud615 key-value \uc800\uc7a5\uc18c\uc774\ub2e4.**  \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294 \uae30\ubc18 \uc2a4\ud1a0\ub9ac\uc9c0(backing storage)\ub85c etcd\ub97c \uc0ac\uc6a9\ud558\uace0 \uc788\ub2e4. \\n\\netcd\ub294 Core OS (Red Hat \uc778\uc218)\uc5d0\uc11c \ucc98\uc74c \uac1c\ubc1c\ub418\uc5b4 \ud604\uc7ac\ub294 CNCF Graduated\uac00 \ub418\uc5c8\ub2e4. etcd\ub294 \uac15\ub825\ud55c \uc77c\uad00\uc131\uc744 \ubcf4\uc7a5\ud558\uace0 \ub192\uc740 \uace0\uac00\uc6a9\uc131\uacfc \uc2e0\ub8b0\uc131\uc744 \ubcf4\uc7a5\ud558\uae30 \ub54c\ubb38\uc5d0 \ucfe0\ubc84\ub124\ud2f0\uc2a4\uc758 \u2018\ub2e8\uc77c \uc9c4\uc2e4 \uacf5\uae09\uc6d0\u2019\uc73c\ub85c\uc11c \ubaa8\ub4e0 \uc0c1\ud0dc \ub370\uc774\ud130(\uc608: \uc5b4\ub5a4 \ud30c\ub4dc\uac00 \uc2e4\ud589 \uc911\uc778\uc9c0, \uc5b4\ub5a4 \uc11c\ube44\uc2a4\uac00 \uc788\ub294\uc9c0, \uc124\uc815\uc740 \uc5b4\ub5bb\uac8c \ub418\uc5b4\uc788\ub294\uc9c0 \ub4f1)\ub4e4\uc744 \uc800\uc7a5\ud558\uace0 \uc788\ub2e4.\\n\\n**Fyi)**\\n\\n> etcd\uc758 \uc774\ub984\uc758 \uc720\ub798\\n\\netcd\ub77c\ub294 \uc774\ub984\uc740 \uc720\ub2c9\uc2a4 /etc \ud3f4\ub354\uc640 distributed \uc2dc\uc2a4\ud15c\uc774\ub780 \uc544\uc774\ub514\uc5b4\uc5d0\uc11c \uc720\ub798\ub418\uc5c8\uace0 distributed etc\ub77c\ub294 \uc758\ubbf8\ub97c \uac00\uc9c4\ub2e4\\n\\n\ucd9c\ucc98: https://smileostrich.tistory.com/entry/etcd\\n> \\n\\n### **\u2018\ubd84\uc0b0 \uc800\uc7a5\u2019\uc774\ub780?**\\n\\n![image.png](/img/nodes.png)\\n\\n\ubd84\uc0b0 \uc800\uc7a5\uc740 \ub370\uc774\ud130\ub97c \ud55c \uacf3\uc5d0 \uc800\uc7a5\ud558\ub294 \uac83\uc774 \uc544\ub2c8\ub77c **\uc5ec\ub7ec \uac1c\uc758 \ubd84\ub9ac\ub41c \uc7a5\uce58\ub098 \ub178\ub4dc\uc5d0 \ub370\uc774\ud130\ub97c \ubd84\uc0b0\ud558\uc5ec \uc800\uc7a5\ud558\ub294 \ubc29\uc2dd\uc73c\ub85c \ub370\uc774\ud130\uc758 `\uc548\uc815\uc131`, `\ud655\uc7a5\uc131` \uc744 \uc704\ud55c \uae30\uc220\uc774\ub2e4.  (\uc77c\ubd80 \uc131\ub2a5 \ud5a5\uc0c1\ub3c4 \uae30\ub300\ud560 \uc218 \uc788\uc74c)**\\n\\n- **\uace0\uac00\uc6a9\uc131:** \ud558\ub098\uc758 \ub178\ub4dc\uc5d0 \ubb38\uc81c\uac00 \uc0dd\uaca8\ub3c4 \ub2e4\ub978 \uc7a5\uce58\uc5d0 \uc800\uc7a5\ub41c \ub370\uc774\ud130\ub294 \uc548\uc815\uc801\uc73c\ub85c \uc720\uc9c0\ub418\uc5b4 \uc11c\ube44\uc2a4 \uac00\ub2a5\ud558\ub2e4.\\n- **\ud655\uc7a5\uc131:** \ud544\uc694\uc5d0 \ub530\ub77c \uc27d\uac8c \ub178\ub4dc\ub97c \ucd94\uac00\ud574 \uc800\uc7a5\uacf5\uac04\uc744 \ud655\ubcf4\ud560 \uc218 \uc788\ub2e4. \ud558\ub4dc\uc6e8\uc5b4\ub97c \uad50\uccb4\ud558\ub294 scale up \ubc29\uc2dd\ubcf4\ub2e4 \uac04\ub2e8\ud558\uace0 \ubb34\uc911\ub2e8\uc73c\ub85c \ucd94\uac00 \uac00\ub2a5\ud558\ub2e4.\\n- **\uc131\ub2a5\ud5a5\uc0c1:** \uc5ec\ub7ec \uc7a5\uce58\uc5d0 \ubd84\uc0b0\ud558\uc5ec \ub370\uc774\ud130\ub97c \uc800\uc7a5\ud558\uae30 \ub54c\ubb38\uc5d0 \ub370\uc774\ud130 \uc804\uc1a1 \uc18d\ub3c4\uc640 \ucffc\ub9ac \uc18d\ub3c4\uac00 \ube68\ub77c\uc9c4\ub2e4.\\n    - \uac19\uc740 \uc9c0\uc5ed\uc758 \ub178\ub4dc\ub07c\ub9ac \ud1b5\uc2e0\ud558\uc5ec RTT \ucd5c\uc18c\ud654 \ud560 \uc218 \uc788\ub2e4\ub294 \uc810 Client\uac00 \ubd84\uc0b0\ub418\uae30 \ub54c\ubb38\uc774 \ub3d9\uc2dc\uc131\uc774\ub098 \ub300\uae30\uc5f4\uc774 \ube44\uad50\uc801 \uc904\uc5b4\ub4dc\ub294 \uacbd\uc6b0\ub9cc \ud5a5\uc0c1\ub420 \uc218 \uc788\uc74c\\n\\n### **\ubd84\uc0b0 \uc800\uc7a5\uc744 \uc704\ud55c \ud2b8\ub808\uc774\ub4dc \uc624\ud504\ub294?**\\n\\n<img src=\\"/img/cap.png\\" alt=\\"cap.png\\" style={{display: \'block\', marginLeft: \'auto\', marginRight: \'auto\'}} />\\n\\n\\n\ubd84\uc0b0 \uc800\uc7a5\uc758 Trade Off\ub294 \uc775\ud788 CAP \uc774\ub860\uc73c\ub85c \uc124\uba85\ub418\uace0 \uc788\ub2e4. \ubd84\uc0b0 \uc800\uc7a5\uc740 HA(High Availability)\ub97c \uc704\ud574 \ub370\uc774\ud130\ub97c \uc5ec\ub7ec \ub178\ub4dc\uc5d0 \uc800\uc7a5\ud558\uae30 \ub54c\ubb38\uc5d0 \ub370\uc774\ud130 \uc77c\uad00\uc131 \uc720\uc9c0\uc5d0 \ub300\ud55c \ub192\uc740 \uc5d4\uc9c0\ub2c8\uc5b4\ub9c1 \ube44\uc6a9\uc774 \ub530\ub77c\uc628\ub2e4. CAP\ub294 \uc77c\uad00\uc131(Consistency), \uac00\uc6a9\uc131(Availability), \ubd84\ud560 \ub0b4\uc131(Partition Tolerance)\uc744 \ubaa8\ub450 \ub9cc\uc871\ud558\ub294 DB\ub294 \uc5c6\uace0 \ucd5c\ub300 2\uac00\uc9c0 \uc18d\uc131\ub9cc \ub9cc\uc871\ud560 \uc218 \uc788\ub2e4\ub294 \uac83\uc744 \uc124\uba85\ud558\uba70 \uc5b4\ub5a4 \uc6b4\uc601 \uc0c1\ud669(OLTP \uc720\ud615)\uc774\ub0d0\uc5d0 \ub530\ub77c \uc798 \ub450 \uac00\uc9c0 \uc18d\uc131\uc744 \uc120\ud0dd\ud558\uc5ec \uad6c\uc131\ud574\uc57c \ud55c\ub2e4. \ub294 \uac83\uc744 \ub9d0\ud558\ub294 \uc774\ub860\uc774\ub2e4.\\n\\netcd\ub294 \uadf8 \uc911 CP\ub97c \ub9cc\uc871\ud558\ub294 \ub370\uc774\ud130 \ubca0\uc774\uc2a4\ub85c \uac00\uc6a9\uc131\uc744 \uc870\uae08 \ud3ec\uae30\ud558\uace0 \uc77c\uad00\uc131\uc744 \ucfe0\ubc84\ub124\ud2f0\uc2a4\uc640 \uac19\uc740 \ubd84\uc0b0 \uc2dc\uc2a4\ud15c\uc5d0\uc11c \uc720\uc9c0\ud558\ub294 \uac83\uc744 \ub354 \uc911\uc2dc\ud55c\ub2e4.  \uadf8\ub807\uc9c0\ub9cc etcd\uc758 HA\uac00 \ubd80\uc871\ud558\ub2e4\ub294 \uc758\ubbf8\ub294 \uc544\ub2c8\ub2e4. \uc2e4\uc81c\ub85c\ub294 Raft \ud569\uc758 \uc54c\uace0\ub9ac\uc998\uc744 \ud1b5\ud574 \uc815\uc871\uc218(Quorum) \uac1c\ub150\uc744 \uc801\uc6a9\ud558\uc5ec \ubd84\uc0b0 \ud658\uacbd\uc5d0\uc11c\ub3c4 \uac15\ud55c \uc77c\uad00\uc131\uc744 \uc720\uc9c0\ud558\uba74\uc11c \uc801\uc808\ud55c \uac00\uc6a9\uc131\uc744 \ud655\ubcf4\ud55c\ub2e4. (\uc774 \uc815\uc871\uc218 \uac1c\ub150\uc5d0 \ub300\ud574\uc11c\ub294 \ub098\uc911\uc5d0 \ub354 \uae4a\uc774 \uc54c\uc544\ubcf4\uc790)\\n\\n### **\uadf8\ub807\ub2e4\uba74 Key-Value \uc800\uc7a5\uc18c\ub780 \ubb34\uc5c7\uc77c\uae4c?**\\n\\nKey-Value \uc800\uc7a5\uc18c(Key-Value Store)\ub294 \uac00\uc7a5 \ub2e8\uc21c\ud55c \ud615\ud0dc\uc758 NoSQL \ub370\uc774\ud130\ubca0\uc774\uc2a4 \uc911 \ud558\ub098\ub85c, \ub370\uc774\ud130\ub97c\xa0**\uace0\uc720\ud55c \ud0a4(Key)\uc640 \uadf8\uc5d0 \ud574\ub2f9\ud558\ub294 \uac12(Value)\uc758 \uc30d**\uc73c\ub85c \uc800\uc7a5\ud558\uace0 \uac80\uc0c9\ud560 \uc218 \uc788\ub2e4.\\n\\n```json\\n{\\n  \\"user:1001\\": {\\n    \\"name\\": \\"\ud64d\uae38\ub3d9\\",\\n    \\"email\\": \\"hong@example.com\\",\\n    \\"age\\": 30\\n  }\\n}\\n```\\n\\n**Fyi)** \\n- NoSQL\uc758 \uc885\ub958\uc5d0\ub294 document\ub3c4 \uc788\ub294\ub370 key-value\ub294 \uc2ec\ud50c\ud558\uac8c key\ub85c\ub9cc \uac80\uc0c9\ud560 \uc218 \uc788\ub2e4. \uc774\ub7ec\ud55c \uc810\uc774 \ub0b4\ubd80 \ud544\ub4dc\ub97c \uc0ac\uc6a9\ud574 \uc870\uac74\uc744 \uac78 \uc218 \uc788\ub294 document db\uc640\ub294 \uc880 \ub2e4\ub974\ub2e4.\\n\\n### \uadf8\ub7fc etcd\uc5d0\uc11c \uc5b4\ub5a4 \uac83\ub4e4\uc774 key\ub85c \uc4f0\uc774\uace0 value\ub85c \uc0ac\uc6a9\ub420\uae4c?\\n\\n### **key:** \\n\\netcd\uc5d0 \uc800\uc7a5\ub418\ub294 \ud0a4\ub294 \uc77c\ubc18\uc801\uc73c\ub85c \ub2e4\uc74c\uacfc \uac19\uc740 \uacc4\uce35\uc801\uc778 \uacbd\ub85c(path-like) \uad6c\uc870\ub97c \uac00\uc9c4\ub2e4 **\uc608\uc2dc:** `/<prefix>/<resource_type>/<namespace>/<resource_name>`\\n\\n- **prefix:**\\n    - \uc77c\ubc18\uc801\uc73c\ub85c `/registry` \ub610\ub294 \uc720\uc0ac\ud55c \uace0\uc815\ub41c prefix\uac00 \uc0ac\uc6a9\ub41c\ub2e4. \uc774\ub294 \ucfe0\ubc84\ub124\ud2f0\uc2a4 API \uac1d\uccb4\ub4e4\uc774 \uc800\uc7a5\ub418\ub294 \uae30\ubcf8 \uacbd\ub85c\ub97c \ub098\ud0c0\ub0b4\uba70 \ub2e4\ub978 \uc2dc\uc2a4\ud15c\ub3c4 etcd\ub97c \uc0ac\uc6a9\ud560 \uacbd\uc6b0 \uc790\uccb4 prefix\uac00 \uc0ac\uc6a9\ub41c\ub2e4.\\n- **resource type:**\\n    - \ucfe0\ubc84\ub124\ud2f0\uc2a4\uc758 \ub9ac\uc18c\uc2a4\uc758 \uc885\ub958\ub97c \ub098\ud0c0\ub0b8\ub2e4. (\uc608\uc2dc: pods, services, deployments, nodes \ub4f1 \uac70\uc758 \ubaa8\ub4e0 API \uac1d\uccb4 \ud0c0\uc785\uc774 \ud574\ub2f9\ub41c\ub2e4.)\\n- **namespace:**\\n    - \ud574\ub2f9 \ub9ac\uc18c\uc2a4\uac00 \uc18d\ud55c \ub124\uc784\uc2a4\ud398\uc774\uc2a4\uc774\ub2e4.\\n- **resource_name:**\\n    - \ud574\ub2f9 \ub9ac\uc18c\uc2a4\uc758 \uace0\uc720\ud55c \uc774\ub984\uc774\ub2e4.\\n    - `kubectl get <resource_type> <resource_name>`\uc5d0\uc11c \uc0ac\uc6a9\ud558\ub294 \uadf8 \uc774\ub984\uc774\ub2e4.\\n- **\uc608\uc2dc:**\\n    - **Pod**:\xa0/registry/pods/default/my-nginx-pod-xyz123\\n    - **Service**:\xa0/registry/services/kube-system/kube-dns\\n    - **ConfigMap**:\xa0/registry/configmaps/production/app-config\\n\\n> **Hands On - Key \uc870\ud68c**\\n> \\n\\n```bash\\netcdctl --endpoints=https://127.0.0.1:2379 \\\\\\n  --cacert=/etc/kubernetes/pki/etcd/ca.crt \\\\\\n  --cert=/etc/kubernetes/pki/etcd/server.crt \\\\\\n  --key=/etc/kubernetes/pki/etcd/server.key \\\\\\n  get / --prefix --keys-only\\n```\\n\\n![image.png](/img/kvstore.png)\\n\uc704 \uba85\ub839\uc73c\ub85c \uc870\ud68c\uc2dc \ub4f1\ub85d\ub41c Key\ub4e4\uc744 \uc870\ud68c\uac00 \uac00\ub2a5\ud558\ub2e4.\\n\\n### **Value:**\\n\\nValue\ub85c\ub294 \uc8fc\ub85c \uc6b0\ub9ac\uac00\xa0`kubectl get <resource> <name> -o yaml`\xa0\uc744 \ud1b5\ud574 \uc870\ud68c\ub418\ub294 \ub0b4\uc6a9\uc744 \uac00\uc9c0\uace0 \uc788\ub2e4. \uc8fc\ub85c `apiVersion`, `kind`, `metadata`, `spec` \uc640 \uac19\uc740 \ud544\ub4dc\ub4e4\uc774 \ud3ec\ud568\ub418\uc5b4 \uc788\uc73c\uba70 \ubcf4\ud1b5 json format\uc73c\ub85c \uc800\uc7a5\ub418\uc5b4 \uc788\ub2e4. \\n\\n> **Hands On - value \uc870\ud68c**\\n> \\n\\n```bash\\netcdctl --endpoints=https://127.0.0.1:2379 \\\\\\n  --cacert=/etc/kubernetes/pki/etcd/ca.crt \\\\\\n  --cert=/etc/kubernetes/pki/etcd/server.crt \\\\\\n  --key=/etc/kubernetes/pki/etcd/server.key \\\\\\n  get /registry/apiextensions.k8s.io/customresourcedefinitions/addresspools.metallb.io \\n```\\n\\n![image.png](/img/kvstore-2.png)\\n\\n---\\n\\n## \uc65c \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294 etcd\ub97c backing storage\ub85c \ucc44\ud0dd \ud588\uc744\uae4c?\\n\\n> \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294 \uad00\uacc4\ud615 \ub370\uc774\ud130\ubca0\uc774\uc2a4\ub098 \ub2e4\ub978 NoSQL \ub300\uc2e0 \uc65c etcd\ub97c \uc120\ud0dd\ud588\uc744\uae4c?\\n\\netcd\ub294 CAP \uc774\ub860\uacfc PACELC \uc774\ub860\uc5d0\uc11c `CP/EL`\uc5d0 \uc18d\ud55c\ub2e4 etcd\ub294 CP(Consistency & Partition Tolerance)\ub97c \uc120\ud0dd\ud55c \ubd84\uc0b0 \uc800\uc7a5\uc18c\uc774\uae30\uc5d0 \uac15\ub825\ud55c \uc77c\uad00\uc131\uc744 \uc704\ud574 Availability\ub97c \ud76c\uc0dd\ud558\uba70 \uc815\uc0c1 \uc0c1\ud669(\ud30c\ud2f0\uc158\uc774 \uc5c6\ub294 \uacbd\uc6b0)\uc5d0\ub294 Else (\ub9cc\uc57d \ud30c\ud2f0\uc158\uc774 \uc5c6\ub2e4\uba74), Latency\uc640 Consistency \uac04\uc758 \ud2b8\ub808\uc774\ub4dc\uc624\ud504\ub97c \uace0\ub824\ud558\ub294\ub370, etcd\ub294 \ub0ae\uc740 \uc9c0\uc5f0 \uc2dc\uac04(Latency)\uc744 \uc720\uc9c0\ud558\uba74\uc11c\ub3c4 \uc77c\uad00\uc131(Consistency)\uc744 \uc81c\uacf5\ud558\ub824 \ud55c\ub2e4\\n\\n**[\uac15\ub825\ud55c \uc77c\uad00\uc131\uc744 \ubcf4\uc7a5\ud574\uc900\ub2e4]**\\n\\n1. \ucfe0\ubc84\ub124\ud2f0\uc2a4\uc758 \ubaa8\ub4e0 \ucef4\ud3ec\ub10c\ud2b8(api server, scheduler, controller \ub4f1)\ub294 **\ud56d\uc0c1 \ub3d9\uc77c\ud55c \ucd5c\uc2e0 \uc0c1\ud0dc \uc815\ubcf4\ub97c \ubc14\ub77c\ubd10\uc57c \ud55c\ub2e4.** \ub9cc\uc77c \ubaa8\ub4e0 \ub370\uc774\ud130\uac00 \ucd5c\uc2e0 \uc0c1\ud0dc\ub85c \uc720\uc9c0\uac00 \ub418\uc9c0 \uc54a\ub294\ub2e4\uba74 pod \uc2a4\ucf00\uc904\ub9c1\uc774 \uc774\uc0c1\ud558\uac8c \uaf2c\uc5ec \uc2e4\uc81c\ub85c\ub294 \ub9ac\uc18c\uc2a4\uac00 \ubd80\uc871\ud574 \uc2a4\ucf00\uc904\ub9c1 \uc548\ub418\ub294 \uac83\uacfc \uac19\uc740 \ubcf5\uc7a1\ud55c \ub370\uc774\ud130 \ubd88\uc77c\uce58\uac00 \ubc1c\uc0dd\ud560 \uc218 \uc788\ub2e4.\\n2. \uc5ec\uae30\uc5d0 etcd\ub294 \uc548\uc131 \ub9de\ucda4\uc778\ub370 Raft \ud569\uc758 \uc54c\uace0\ub9ac\uc998\uc744 \ud1b5\ud574 \ud55c \ubc88 \ucee4\ubc0b\ub41c \ub370\uc774\ud130\ub294 \ubaa8\ub4e0 \ub178\ub4dc\uc5d0\uc11c \ub3d9\uc77c\ud558\uac8c \uc870\ud68c\ub418\uc5b4 \ud074\ub7ec\uc2a4\ud130 \uc804\uccb4\uc5d0 \uac78\uccd0 \ub370\uc774\ud130\uc758 \uac15\ub825\ud55c \uc77c\uad00\uc131\uc774 \ubcf4\uc7a5\ub41c\ub2e4.\\n\\n**[\uc548\uc815\uc801\uc778 Watch \ub9e4\ucee4\ub2c8\uc998\uc744 \uc9c0\uc6d0\ud558\uc5ec \ucd5c\uc2e0 \uc0c1\ud0dc\ub97c \ud56d\uc0c1 \ubc18\uc601\ud55c\ub2e4]**\\n\\n1. \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294 \uc120\uc5b8\uc801 API\ub97c \uae30\ubc18\uc73c\ub85c \ub3d9\uc791\ud55c\ub2e4. \uc0ac\uc6a9\uc790\uac00 \uc6d0\ud558\ub294 \uc0c1\ud0dc\ub97c API \uc11c\ubc84\uc5d0 \uc804\ub2ec\ud558\uba74, \uac01\uc885 \ucee8\ud2b8\ub864\ub7ec \ub4f1\uc774 \uc0c1\ud0dc\ub97c \uac10\uc9c0(watch) \ud558\uace0 \ud604\uc7ac \uc0c1\ud0dc\ub97c \uc6d0\ud558\ub294 \uc0c1\ud0dc\ub85c \ub9cc\ub4e4\uc5b4\uac04\ub2e4. \uc774\ub97c \uc704\ud574\uc120 \ud2b9\uc815 \ub370\uc774\ud130 \ubcc0\uacbd \uc0ac\ud56d\uc744 \uc548\uc815\uc801\uc73c\ub85c \uc21c\uc11c\ub300\ub85c \uac10\uc9c0\ud560 \uc218 \uc788\ub294 \uae30\ub2a5\uc774 \ud544\uc218\uc801\uc774\ub2e4.\\n2. etcd\ub294 \ud2b9\uc815 key \ub610\ub294 key prefix\uc5d0 \ub300\ud55c \ubcc0\uacbd \uc774\ubca4\ud2b8\ub97c \uc2e4\uc2dc\uac04\uc73c\ub85c \uad6c\ub3c5\ud560 \uc218 \uc788\ub294 Watch API\ub97c \uc81c\uacf5\ud55c\ub2e4. \ub610 **MVCC (Multi Version Concurrency Control) \ub355\ubd84\uc5d0 \uacfc\uac70 \ud2b9\uc815 \uc2dc\uc810\ubd80\ud130 \ubcc0\uacbd \uc0ac\ud56d\ub3c4 \uc21c\ucc28\uc801\uc73c\ub85c \uc54c \uc218 \uc788\ub2e4**.\\n    \\n    etcd\uc758 watch\ub294 `resourceVersion`\uc744 \uae30\ubc18\uc73c\ub85c \uc774\ubca4\ud2b8\uc758 \uc21c\uc11c\ub97c \ubcf4\uc7a5\ud574\uc8fc\uae30 \ub54c\ubb38\uc5d0 \ucee8\ud2b8\ub864\ub7ec\ub4e4\uc774 \ub193\uce58\ub294 \uc774\ubca4\ud2b8 \uc5c6\uc774 \uc815\ud655\ud558\uac8c \uc0c1\ud0dc \ubcc0\ud654\ub97c \ub530\ub77c\uac08 \uc218 \uc788\uc73c\uba70, watch\uac00 \ub04a\uacbc\ub2e4\uac00 \uc7ac\uc5f0\uacb0\ub420 \ub54c \uc774\uc804 `resourceVersion`\uc744 \uae30\uc900\uc73c\ub85c \ubcc0\uacbd\ub41c \ubd80\ubd84\ub9cc \ud6a8\uc728\uc801\uc73c\ub85c \ucc98\ub9ac\ud560 \uc218 \uc788\ub2e4.\\n    \\n\\n### etcd\ub294 \ub300\uaddc\ubaa8 \ub370\uc774\ud130\ub97c \uc800\uc7a5\ud560 \uc218 \uc788\uc744\uae4c? - \uc0e4\ub529\uc774 \ud544\uc694\ud558\uc9c0 \uc54a\uc744\uae4c?\\n\\n> \ub300\uaddc\ubaa8 \uc11c\ube44\uc2a4\uc5d0\uc11c etcd \ud074\ub7ec\uc2a4\ud130 \uc6b4\uc601\uc744 \uc704\ud55c \uace0\ubbfc\\n> \\n\\n\ubb38\ub4dd \ub300\uaddc\ubaa8 \ud074\ub7ec\uc2a4\ud130\ub97c \uc6b4\uc601\ud55c\ub2e4\uba74 \uc218\ucc9c\uac1c\uc758 Pod\uac00 \uc218\ubc31\uc758 \uc6cc\ud06c\ub85c\ub4dc \uba54\ud0c0\ub370\uc774\ud130\uac00 \uc800\uc7a5\ub418\uc5b4\uc57c \ud55c\ub2e4\uba74 \uc0e4\ub529 \uac1c\ub150\uc774 \ud544\uc694\ud558\uc9c0 \uc54a\uc744\uae4c \ud588\ub2e4. \uc6b0\uc120, etcd\ub294 \uc0e4\ub529\uc5d0 \uc801\ud569\ud558\uc9c0 \uc54a\ub2e4. \uc0e4\ub529\uc740 \ud2b9\uc815 \uc54c\uace0\ub9ac\uc998(Hash, Rage \ub4f1)\uc744 \uc0ac\uc6a9\ud574 \ub370\uc774\ud130\ub97c \ud2b9\uc815 \uc0e4\ub4dc\ub85c \ubd84\uc0b0\ud558\uc5ec \uc800\uc7a5\ud558\ub294 \uac83\uc73c\ub85c \uc2a4\ud1a0\ub9ac\uc9c0 \ud655\uc7a5\uc744 \uc8fc \ubaa9\ud45c\ub85c\ud55c\ub2e4.\\n\\n\ud558\uc9c0\ub9cc etcd\ub294 \ub370\uc774\ud130 \uc77c\uad00\uc131\uc5d0 \ub354 \uc9d1\uc911\ud558\ub294 \uac83\uc73c\ub85c \ubaa8\ub4e0 \ub370\uc774\ud130\uac00 \uacfc\ubc18\uc218 \uc774\uc0c1\uc758 \ub178\ub4dc\uc5d0 \ub3d9\uc77c\ud558\uac8c Replication \ub418\uc5b4 \uc788\uc5b4\uc57c\ud55c\ub2e4. \ub530\ub77c\uc11c \uc0e4\ub529 \uac1c\ub150\uacfc\ub294 \ub9de\uc9c0 \uc54a\ub2e4.\\n\\n**\uadf8\ub807\ub2e4\uba74? \uace0\uc131\ub2a5\uc740 \uc5b4\ub5bb\uac8c \uc124\uacc4\ud558\uba74 \uc88b\uc744\uae4c?**\\n\\n\uc6b0\uc120 \ub2e8\uc21c\ud788 \uc0dd\uac01\ud558\uba74 etcd \ud074\ub7ec\uc2a4\ud130\uc758 scale out\uc744 \uc27d\uac8c \uace0\ub824\ud574\ubcfc \uc218 \uc788\ub2e4. \ud558\uc9c0\ub9cc etcd \ud074\ub7ec\uc2a4\ud130\uc758 scale out\uc740 \ubcf5\uc81c \ub3d9\uae30\ud654 \uc2dc\uac04\uc774 \ub354 \uc624\ub798\uac78\ub9b4 \uc218 \uc788\ub2e4. \ub530\ub77c\uc11c \ub300\uaddc\ubaa8 \ud074\ub7ec\uc2a4\ud130\uc5d0\uc11c etcd\ub294 \ub2e4\uc74c\uacfc \uac19\uc740 \ucd5c\uc801\ud654 \uc804\ub7b5\uc744 \ub530\ub97c \uc218 \uc788\ub2e4.\\n\\n1. \ud558\ub4dc\uc6e8\uc5b4 \ucd5c\uc801\ud654\\n    1. \ube60\ub978 I/O\ub97c \uc704\ud574 NVMe SSD\uc744 \ud544\uc218\ub85c \uc0ac\uc6a9\ud55c\ub2e4.\\n    2. \ub300\uaddc\ubaa8 \ud074\ub7ec\uc2a4\ud130\uc5d0\uc11c Watch API\ub294 \ub9ce\uc740 \uba54\ubaa8\ub9ac \uc0ac\uc6a9\uc744 \ud544\uc694\ub85c\ud55c\ub2e4. \ub530\ub77c\uc11c RAM\uc744 \ucda9\ubd84\ud788 \ud655\ubcf4\ud558\ub294 \uac83\uc774 \uc911\uc694\ud558\ub2e4.\\n2. \ud074\ub7ec\uc2a4\ud130 \ubd84\ub9ac\\n    1. \uac00\uc7a5 \ucd94\ucc9c\ub418\ub294 \uac83\uc73c\ub85c \ubaa9\uc801\uc5d0 \ub9de\uac8c \ud074\ub7ec\uc2a4\ud130\ub97c \ubd84\ub9ac\ud558\ub294 \uac83\uc774 \uc88b\ub2e4.\\n    2. \uc11c\ube44\uc2a4 \ud074\ub7ec\uc2a4\ud130\uc640 \uc6b4\uc601 \ud074\ub7ec\uc2a4\ud130\ub97c \ubd84\ub9ac\ud558\ub294 \uac83\uc758 \ubc29\ubc95\uc73c\ub85c \ud558\ub098\uc758 Control plane\uc5d0 \ubaa8\ub4e0 \uc694\uccad\uc774 \ubab0\ub9ac\ub294 \uac83\uc77c \ubc29\uc9c0\ud574\uc57c \ud55c\ub2e4.\\n    3. \ubb3c\ub860, \ubcf4\uc548\uacfc \uac19\uc740 \ucd94\uac00 \ud2b8\ub808\uc774\ub4dc \uc624\ud504\uac00 \uc788\uae34\ud558\ub2e4.\\n3. etcd\uc758 \uc815\uae30\uc801\uc778 \ucd5c\uc801\ud654\\n    1. `Compaction:`\xa0etcd\ub294 MVCC(Multi-Version Concurrency Control)\ub97c \uc0ac\uc6a9\ud558\ubbc0\ub85c \uacfc\uac70 \ubc84\uc804\uc758 \ud0a4\ub4e4\uc774 \uacc4\uc18d \uc313\uc778\ub2e4.\xa0compaction\uc744 \ud1b5\ud574 \uacfc\uac70 \ubc84\uc804\uc744 \uc815\ub9ac\ud558\uc5ec \uc800\uc7a5 \uacf5\uac04\uc744 \ud655\ubcf4\ud558\uace0 \uc131\ub2a5\uc744 \uc720\uc9c0\ud574\uc57c \ud55c\ub2e4. (Kubernetes\ub294 auto\xa0compaction \uc9c0\uc6d0) \\n        \\n        (revesion\uacfc compaction\uc5d0 \ub300\ud55c \ub0b4\uc6a9\uc740 \uce74\uce74\uc624 [\uae30\uc220 \ube14\ub85c\uadf8](https://www.notion.so/Inside-etcd-K8s-etcd-1ed64745317080599a2cf9ec7e9254af?pvs=21)\uc758 \uae00\ub85c \ub300\uccb4\ud569\ub2c8\ub2e4.)\\n        \\n    2. `Defragmentation:`\xa0Compaction \ud6c4\uc5d0\ub3c4 \ub0b4\ubd80\uc801\uc73c\ub85c \uc870\uac01\ud654\ub41c \uacf5\uac04\uc774 \ub0a8\uc544\uc788\uc744 \uc218 \uc788\ub2e4.\xa0`defragmentation`\uc744 \ud1b5\ud574 \uc2e4\uc81c \ub514\uc2a4\ud06c \uacf5\uac04\uc744 \ud68c\uc218\ud558\uace0 \ub370\uc774\ud130\ubca0\uc774\uc2a4 \ud30c\uc77c \ud06c\uae30\ub97c \uc904\uc77c\xa0\uc218 \uc788\ub2e4. \\n\\n---\\n\\n## ETCD \ub3d9\uae30\ud654 \uba54\ucee4\ub2c8\uc998 (Raft \ud569\uc758 \uc54c\uace0\ub9ac\uc998) \uc774 \uc5b4\ub5bb\uac8c \ub420\uae4c?\\n\\n<img src=\\"/img/raft.png\\" alt=\\"raft.png\\" style={{display: \'block\', marginLeft: \'auto\', marginRight: \'auto\'}} />\\n\\n\ub4dc\ub514\uc5b4 \ucc98\uc74c \ud0d0\uad6c\ud558\uace0\uc790 \ud588\ub358 etcd\uc758 \uac15\ub825\ud55c \uc77c\uad00\uc131\uc758 \uba54\ucee4\ub2c8\uc998\uc778 Raft \ud569\uc758 \uc54c\uace0\ub9ac\uc998\uc5d0 \ub300\ud574 \uc774\uc57c\uae30\ud574\ubcf4\uc790.\\n\\n**etcd\ub294 `Replicated state machine(\uc774\ud558 RSM)`\uc774\ub2e4.** \ubd84\uc0b0 \ucef4\ud4e8\ud305 \ud658\uacbd\uc5d0\uc11c \uc11c\ubc84\uac00 \uba87 \uac1c \ub2e4\uc6b4\ub418\uc5b4\ub3c4 \uc798 \ub3d9\uc791\ud558\ub294 \uc2dc\uc2a4\ud15c\uc744 \ub9cc\ub4e4\uace0\uc790 \ud560 \ub54c \uc120\ud0dd\ud558\ub294 \ubc29\ubc95\uc758 \ud558\ub098\ub85c, State Machine Replication\uc774 \uc788\ub294\ub370 \uc774\ub294 \ub611\uac19\uc740 \ub370\uc774\ud130\ub97c \uc5ec\ub7ec \uc11c\ubc84\uc5d0 \uacc4\uc18d\ud558\uc5ec \ubcf5\uc81c\ud558\ub294 \uac83\uc774\uba70, \uc774 \ubc29\ubc95\uc73c\ub85c \uc0ac\uc6a9\ud558\ub294 \uba38\uc2e0\uc744 RSM\uc774\ub77c \ud55c\ub2e4.\\n\\nRSM\uc740 command\uac00 \ub4e4\uc5b4\uc788\ub294 Log \ub2e8\uc704\ub85c \ub370\uc774\ud130\ub97c \ucc98\ub9ac\ud558\ub294\ub370 \ub370\uc774\ud130\uc758 write\ub97c log append\ub77c \ubd80\ub974\uba70, \uba38\uc2e0\uc740 \ubc1b\uc740 log\ub97c \uc21c\uc11c\ub300\ub85c \ucc98\ub9ac\ud558\ub294 \ud2b9\uc9d5\uc744 \uac16\ub294\ub2e4. \ud558\uc9c0\ub9cc, \ub611\uac19\uc740 \ub370\uc774\ud130\ub97c \uc5ec\ub7ec \uc11c\ubc84\uc5d0 \ubcf5\uc81c\ud574\ub1a8\ub2e4\uace0 \ud574\uc11c \ubaa8\ub4e0 \uac8c \ud574\uacb0\ub418\uc9c0\ub294 \uc54a\ub294\ub2e4.\\n\\n\uc624\ud788\ub824 \ub354 \ubcf5\uc7a1\ud55c \ubb38\uc81c\uac00 \uc0dd\uae30\uae30\ub3c4 \ud558\ub294\ub370 \uacac\uace0\ud55c \ud55c RSM\uc744 \ub9cc\ub4e4\uae30 \uc704\ud574\uc11c\ub294 \ub370\uc774\ud130 \ubcf5\uc81c \uacfc\uc815\uc5d0 \ubc1c\uc0dd\ud560 \uc218 \uc788\ub294 \uc5ec\ub7ec \uac00\uc9c0 \ubb38\uc81c\ub97c \ud574\uacb0\ud558\uae30 \uc704\ud574 `\u2018\ud569\uc758\u2019(consensus)`\ub97c \ud655\ubcf4\ud558\ub294 \uac83\uc774 \ud575\uc2ec\uc73c\ub85c, \ud569\uc758(Consensus)\ub97c \ud655\ubcf4\ud55c\ub2e4\ub294 \uac83\uc740 RSM\uc774 \uc544\ub798 4\uac00\uc9c0 \uc18d\uc131\uc744 \ub9cc\uc871\ud55c\ub2e4\ub294 \uac83\uacfc \uc758\ubbf8\uc774\uba70 etcd\ub294 \uc774\ub97c \uc704\ud574 Raft \uc54c\uace0\ub9ac\uc998\uc744 \uc0ac\uc6a9\ud558\uc600\ub2e4.\\n\\n| \uc18d\uc131 | \uc124\uba85 |\\n| --- | --- |\\n| Safety | \ud56d\uc0c1 \uc62c\ubc14\ub978 \uacb0\uacfc\ub97c \ub9ac\ud134\ud574\uc57c \ud569\ub2c8\ub2e4. |\\n| Available | \uc11c\ubc84\uac00 \uba87 \ub300 \ub2e4\uc6b4\ub418\ub354\ub77c\ub3c4 \ud56d\uc0c1 \uc751\ub2f5\ud574\uc57c \ud569\ub2c8\ub2e4. |\\n| Independent from timing | \ub124\ud2b8\uc6cc\ud06c \uc9c0\uc5f0\uc774 \ubc1c\uc0dd\ud574\ub3c4 \ub85c\uadf8\uc758 \uc77c\uad00\uc131\uc774 \uae68\uc838\uc11c\ub294 \uc548\ub429\ub2c8\ub2e4. |\\n| Reactivity | \ubaa8\ub4e0 \uc11c\ubc84\uc5d0 \ubcf5\uc81c\ub418\uc9c0 \uc54a\uc558\ub354\ub77c\ub3c4 \uc870\uac74\uc744 \ub9cc\uc871\ud558\uba74 \ube60\ub974\uac8c \uc694\uccad\uc5d0 \uc751\ub2f5\ud574\uc57c \ud569\ub2c8\ub2e4. |\\n\\n### **1. Raft \ud569\uc758 \uc54c\uace0\ub9ac\uc998\uc740 \ubb34\uc5c7\uc77c\uae4c?**\\n\\nRaft \ud569\uc758 \uc54c\uace0\ub9ac\uc998\uc740 \uc5ec\ub7ec \ub178\ub4dc\ub85c \uad6c\uc131\ub41c \ubd84\uc0b0 \uc2dc\uc2a4\ud15c\uc5d0\uc11c \ubaa8\ub4e0 \ub178\ub4dc\uac00 \uc77c\uad00\ub41c \uc0c1\ud0dc\ub97c \uac00\uc9c8 \uc218 \uc788\uac8c \ud574\uc8fc\ub294 \uc54c\uace0\ub9ac\uc998\uc774\ub2e4. Raft \ud569\uc758 \uc54c\uace0\ub9ac\uc998\uc740 \uc774\ub984\uc5d0\uc11c\ub3c4 \uc54c \uc218 \uc788\ub4ef  \ubd84\uc0b0\xa0\uc2dc\uc2a4\ud15c \ub0b4\uc758 \ubaa8\ub4e0 (\uc815\uc0c1\uc801\uc778) \ub178\ub4dc\ub4e4\uc774\xa0**\ub2e8\uc77c \uac12\uc5d0 \ub3d9\uc758**\ud558\ub294 \uac83\uc744 \ubaa9\ud45c\ud55c\ub2e4. \\n\\n### **2. \uc5b4\ub5bb\uac8c \ub3d9\uc791\ud558\ub294\uac00? - \ub9ac\ub354 \uc120\ucd9c**\\n\\nRaft \ud569\uc758 \uc54c\uace0\ub9ac\uc998\uc744 \uc774\ud574\ud558\uae30 \uc704\ud574 \uc6b0\uc120 **\u2018\ub9ac\ub354 \uc120\ucd9c\u2019** \uc5d0 \ub300\ud55c \uc774\ud574\uac00 \ud544\uc694\ud558\ub2e4.  \ubd84\uc0b0 \uc2dc\uc2a4\ud15c\uc774 Join\ud55c Node\ub4e4\uc740  `1. \ub9ac\ub354 (Leader)` , `2. \ud314\ub85c\uc6cc (Fallower)`,  `3. \ud6c4\ubcf4\uc790 (Candidate)`  3\uac00\uc9c0 \uc911 \ud558\ub098\uc758 \uc0c1\ud0dc\ub97c \uac00\uc9c0\uba70, \ud569\uc758\ub97c \uc704\ud574 \uba85\ub839\uc740 \uc624\uc9c1 \ub9ac\ub354\ub85c\ubd80\ud130 \uc804\ub2ec\ubc1b\uc544\uc57c \ud55c\ub2e4. **\uadf8\ub807\uae30\uc5d0 \uba3c\uc800 \ub9ac\ub354\uac00 \uc120\ucd9c\ub418\uc5b4\uc57c \ud55c\ub2e4.**\\n\\n\ucd5c\ucd08 3\uac1c\uc758 \ub178\ub4dc\ub4e4\uc744 \uc774\uc6a9\ud574 etcd \ud074\ub7ec\uc2a4\ud130\ub97c \uad6c\uc131\ud588\uc744 \ub54c, \uac01 \ub178\ub4dc\ub4e4\uc740 \ubaa8\ub450 follower \uc0c1\ud0dc(state)\uc774\uba70 Term\uc774\ub77c\ub294 \uac12\uc744 0\uc73c\ub85c \uc124\uc815\ud558\uace0 \ub3d9\uc791\uc744 \uc2dc\uc791\ud55c\ub2e4. (Term\uc740 \uc27d\uac8c \uc0dd\uac01\ud558\uba74 \ub9ac\ub354\uc758 \uc784\uae30\uc774\ub2e4.)\\n\\n1. `election timeout \ubc1c\uc0dd:` \uba3c\uc800 \ub9ac\ub354 \ub178\ub4dc\uac00 \uc5c6\ub294 \ucd5c\ucd08\uc758 \uc2dc\uc2a4\ud15c\uc740 \ud314\ub85c\uc6cc\uac00 \ub9ac\ub354\ub85c\ubd80\ud130 `heartbeat`\ub97c \ubc1b\uc9c0 \ubabb\ud558\uae30 \ub54c\ubb38\uc5d0 `election timeout`\uc774 \ud2b8\ub9ac\uac70 \ub41c\ub2e4.\\n2. `\ub9ac\ub354 \uc9c0\uc6d0:` \ud314\ub85c\uc6cc \uc911 \ud55c \uba85\uc774 `election timeout`\uc5d0 \uc758\ud574 **\u2018\ud6c4\ubcf4\uc790\u2019**\uac00 \ub418\ub294\ub370 term \uac12\uc744 1\uc99d\uac00 \uc2dc\ud0a4\uace0 \ud074\ub7ec\uc2a4\ud130\uc5d0 \uc874\uc7ac\ud558\ub294 \ub2e4\ub978 \ud314\ub85c\uc6cc\ub4e4\uc5d0\uac8c `RequestVote RPC call`\uc744 \ubcf4\ub0b8\ub2e4. `RequestVote RPC call`\uc744 \ubc1b\uc740 \ud314\ub85c\uc6cc\ub4e4\uc740 \uc790\uc2e0\uc758 term\uacfc log \uc815\ubcf4\ub97c \ube44\uad50\ud558\uc5ec \uc790\uc2e0\uc758 term\ubcf4\ub2e4 \ud06c\ub2e4\uba74 OK \uc751\ub2f5\uc744 \ub0b4\ub824\uc8fc\uace0 OK \uc751\ub2f5\uc744 \ubc1b\ub294 `\uc9c0\uc6d0\uc790`\ub294 \ubc1b\uc740 OK \uc22b\uc790\uac00 \uc815\uc871\uc218 (Quorum) \uc640 \uac19\ub2e4\uba74  `\ub9ac\ub354`\uac00 \ub41c\ub2e4.\\n3. `\uc900\ube44 \uc644\ub8cc:` \ub9ac\ub354\uac00 \uc120\ucd9c \ub418\uc5c8\uace0, \ub9ac\ub354\ub294 \ub2e4\ub978 \ub178\ub4dc\ub4e4\uc5d0\uac8c heartbeat\uc744 \ubcf4\ub0b4\ub294\ub370 \uc774 \ub54c \uc0ac\uc6a9\ub418\ub294 `Append RPC call`\uc774\ub2e4. call\uc5d0\ub294 \ub9ac\ub354\uc758 Term\uacfc \ubcf4\uc720\ud55c log index \uc815\ubcf4\uac00 \ub4e4\uc5b4\uc788\ub2e4. \uc774\ub97c \uc218\uc2e0\ud55c \ud314\ub85c\uc6cc\ub4e4\uc740 term\uc744 \uc5c5\ub370\uc774\ud2b8 \ud55c\ub2e4. \uc774\ub807\uac8c etcd\ub294 write\uc640 read \uc694\uccad\uc744 \ubc1b\uc744 \uc900\ube44\uac00 \ub418\uc5c8\ub2e4.\\n\\n### **3. \uc5b4\ub5bb\uac8c \ub3d9\uc791\ud558\ub294\uac00? - \ub85c\uadf8 \ubcf5\uc81c**\\n\\n1. `\uc694\uccad \uc218\uc2e0:` \ub9ac\ub354\ub294 \ud074\ub77c\uc774\uc5b8\ud2b8\ub85c\ubd80\ud130 \ubaa8\ub4e0 \uc694\uccad\uc744 \uc218\ub518 \ub300\uae30\ud55c\ub2e4.\\n2. `WAL \uae30\ub85d:` \uc218\uc2e0\ub41c \uba85\ub839\uc744 \ubc14\ud0d5\uc73c\ub85c \uba3c\uc800 \ub85c\uadf8(Log Entry)\ub97c \uc0dd\uc131\ud558\uc5ec \ub85c\uceec WAL (Write-Ahead Log) \uc800\uc7a5\ud55c\ub2e4. \uc774 \ub54c \ub9ac\ub354\ub294 \uc790\uc2e0\uc758 `lastLogIndex` \ub97c \uc5c5\ub370\uc774\ud2b8\ud55c\ub2e4. \\n3. `AppendEntry RPC Call:`  WAL\uc5d0 \ucd94\uac00\ub41c Log Entry\ub294 \ubaa8\ub4e0 \ud314\ub85c\uc6cc\ub4e4\uc5d0\uac8c`AppendEntry RPC` call\uc774 \ud638\ucd9c\ub418\uc5b4 \uc804\ub2ec\ub418\uace0 \ud314\ub85c\uc6cc\ub4e4\uc758 WAL\uc5d0 \uc815\uc0c1\uc801\uc73c\ub85c \ucd94\uac00\ub418\uba74 \ud314\ub85c\uc6cc\ub4e4\uc758 `lastLogIndex` \ub294 \ub9ac\ub354\uc758  `lastLogIndex` \uc640 \uc77c\ucc28\ud788\uac8c \ub41c\ub2e4. \\n4. **`\ucee4\ubc0b \uacb0\uc815 \ubc0f \uc0c1\ud0dc \uba38\uc2e0 \uc801\uc6a9 (\ub9ac\ub354)**:` \ub9ac\ub354\uac00 \uc218\uc2e0\ud55c \uc815\uc0c1 \uc751\ub2f5 \uc218\uac00 \uc804\uccb4 \ub178\ub4dc\uc758 \uacfc\ubc18\uc218\uc5d0 \uc774\ub974\uba74, \ub9ac\ub354\ub294 \ud574\ub2f9 Log Entry\ub97c Commit \ud558\uace0 \ud074\ub77c\uc774\uc5b8\ud2b8\uc5d0\uac8c \uacb0\uacfc\ub97c \ubc18\ud658\ud55c\ub2e4.\\n5. `\ucee4\ubc0b \uc815\ubcf4 \uc804\ud30c \ubc0f \ud314\ub85c\uc6cc\ub4e4\uc758 \uc0c1\ud0dc \uba38\uc2e0 \uc815\ubcf4:` \ub9ac\ub354\ub294 \ub2e4\uc74c AppendEntries RPC (\ud558\ud2b8\ube44\ud2b8 \ud3ec\ud568)\ub97c \ud1b5\ud574 \ud314\ub85c\uc6cc\ub4e4\uc5d0\uac8c \uc5c5\ub370\uc774\ud2b8\ub41c leaderCommit \uc778\ub371\uc2a4\ub97c \uc54c\ub824\uc8fc\uace0 \ud314\ub85c\uc6cc\ub4e4\uc740 \uc774 \uc815\ubcf4\ub97c \ubc14\ud0d5\uc73c\ub85c \uc790\uc2e0\uc758 \ub85c\uceec \ub85c\uadf8 \uc911 \ucee4\ubc0b\ub41c \ud56d\ubaa9\ub4e4\uc744 \uc790\uc2e0\uc758 \uc0c1\ud0dc \uba38\uc2e0\uc5d0 \uc21c\uc11c\ub300\ub85c \uc801\uc6a9\ud55c\ub2e4.\\n\\n### \uad81\uae08\uc99d \uc815\ub9ac!\\n\\n> **Commit\uc774\ub780 \ubb34\uc5c7\uc778\uac00?**\\n> \\n\\n\uc6b0\uc120, \ud314\ub85c\uc6cc \ub4e4\uc5d0 AppendEntry RPC\ub97c \ubcf4\ub0c8\uc744 \ub54c \ud314\ub85c\uc6cc\ub4e4\uc758 WAL\uc5d0 \uc0c8\ub85c\uc6b4 Log Entry\ub97c \ucd94\uac00\ud55c\ub2e4.  \uc774 \uc2dc\uc810\uc774 OK \uc751\ub2f5\uc744 \ubc18\ud658\ud558\ub294 \uac83\uc774\ub2e4. Log Entry\ub97c Commit \ud558\uace0 \ud074\ub77c\uc774\uc5b8\ud2b8\uc5d0\uac8c \uacb0\uacfc\ub97c \ubc18\ud658\ud55c\ub2e4. \ub77c\uace0 \ud588\ub2e4 \uc5ec\uae30\uc11c \uadf8\ub7fc Commit\uc774\ub780 \ubb34\uc5c7\uc77c\uae4c? \\n\\n1. **\ub0b4\uad6c\uc131(Durability) \ud655\ubcf4**: \ud574\ub2f9 \ub85c\uadf8 \ud56d\ubaa9\uc774 \ud074\ub7ec\uc2a4\ud130 \ub0b4\xa0**\uacfc\ubc18\uc218(majority)\uc758 \uc11c\ubc84\uc5d0 \uc548\uc804\ud558\uac8c \ubcf5\uc81c(replicated)\ub418\uc5b4 \uc800\uc7a5**\ub418\uc5c8\ub2e4\ub294 \uac83\uc744 \uc758\ubbf8\ud55c\ub2e4.\\n2. **\uc5b4\ub5bb\uac8c \ubcf4\uc7a5\ud560\uae4c?**\\n    1. wal\uc5d0 log\uac00 append \ub41c\ub2e4\ub294 \uac83\uc740 \uc5c4\uaca9\ud558\uac8c \ub0b4\uad6c\uc131\uc774 \ubcf4\uc7a5\ub41c\ub2e4\ub294 \uac83\uc778\ub370 \uc774\ub294 fsync() \ub77c\ub294 \uc2dc\uc2a4\ud15c \ucf5c\uc5d0 \uc758\ud574 \ubcf4\uc7a5\ub41c\ub2e4. fsync()\ub294 \ub3d9\uae30\ud568\uc218\ub85c \uc2e4\uc81c write \ub420 \ub54c\uae4c\uc9c0 \ub300\uae30\ud558\uace0 fsync()\ub294 file discripter\ub97c \uc778\uc790\ub85c \ubc1b\ub294\ub370 fd\uc758 \ub0b4\uc6a9\uc774 \ubaa8\ub450 \ub3d9\uae30\ud654\ub41c\ub2e4.\\n        \\n        ```c\\n        #include <unistd.h>\\n        // sync() \ud568\uc218\uc640 \ub2ec\ub9ac \ud558\ub4dc\ub514\uc2a4\ud06c\uac00 \ub370\uc774\ud130\uc640 \uba54\ud0c0\ub370\uc774\ud130\ub97c \ubaa8\ub450 \uc4f8 \ub54c\uae4c\uc9c0 \uae30\ub2e4\ub838\ub2e4\uac00 \ubc18\ud658\ub41c\ub2e4.\\n        int fsync(int fd);\\n        ```\\n\\n### **\ubcf5\uc81c Deep Dive**\\n\\n> **AppendEntry\uc5d0\ub294 \ubb34\uc5c7\uc774 \uc788\ub098?**\\n> \\n- `term:` \ub9ac\ub354\uc758 \ud604\uc7ac \uc784\uae30 \ubc88\ud638\\n- `leaderId:` \ub9ac\ub354 \uc790\uc2e0\uc758 ID\\n- `prevLogIndex:` \ub9ac\ub354\uac00 \ud314\ub85c\uc6cc\uc5d0\uac8c \ubcf4\ub0b4\ub294\xa0\uc0c8\ub85c\uc6b4 \ub85c\uadf8 \ud56d\ubaa9\ub4e4 \ubc14\ub85c \uc774\uc804 \ub85c\uadf8 \ud56d\ubaa9\uc758\xa0\uc778\ub371\uc2a4. (\ud314\ub85c\uc6cc\uc758\xa0nextIndex[i] - 1\xa0\uac12)\\n- `prevLogTerm:`\xa0prevLogIndex\uc5d0 \ud574\ub2f9\ud558\ub294 \ub85c\uadf8 \ud56d\ubaa9\uc758\xa0**\uc784\uae30 \ubc88\ud638**\xa0(\ub9ac\ub354\uc758\xa0\ub85c\uadf8 \uae30\uc900).\\n- `entries[]:` \uc2e4\uc81c \ubcf5\uc81c\ud560\xa0**\ub85c\uadf8 \ud56d\ubaa9(Log Entry)\ub4e4\uc758 \ubc30\uc5f4**. \uc5ec\uae30\uac00 \ubc14\ub85c \ub85c\uadf8 \ub370\uc774\ud130\uac00 \ub4e4\uc5b4\uac00\ub294 \uacf3\uc785\ub2c8\ub2e4. (\ud558\ud2b8\ube44\ud2b8\uc758 \uacbd\uc6b0 \ube44\uc5b4\uc788\uc744 \uc218 \uc788\uc74c)\\n- `leaderCommit:` \ub9ac\ub354\uac00 \uc54c\uace0 \uc788\ub294, \ud604\uc7ac\uae4c\uc9c0\xa0**\ucee4\ubc0b\ub41c \ub85c\uadf8\uc758 \ub9c8\uc9c0\ub9c9 \uc778\ub371\uc2a4**\xa0(commitIndex).\\n\\n**\ub85c\uadf8 \ud56d\ubaa9 (Log Entry)\uc758 \uad6c\uc870 (Raft \ub17c\ubb38 \uae30\uc900):**\\n\\n- **Command**: \ud074\ub77c\uc774\uc5b8\ud2b8\uac00 \uc694\uccad\ud55c \uc2e4\uc81c \uba85\ub839\uc5b4 (\uc608:\xa0SET x = 3)\\n- **Term**: \uc774 \ub85c\uadf8 \ud56d\ubaa9\uc774\xa0**\ub9ac\ub354\uc5d0 \uc758\ud574 \uc0dd\uc131\ub420 \ub2f9\uc2dc\uc758 \ub9ac\ub354\uc758 \uc784\uae30 \ubc88\ud638**.\\n\\n> **prevLogIndex \uacfc prevLogTerm**\\n> \\n- prevLogIndex\ub294 \ub9ac\ub354\uc758 \uc0c8\ub85c\uc6b4 \ub85c\uadf8 \ud56d\ubaa9\ub4e4 \ubc14\ub85c \uc804 \uc778\ub371\uc2a4 \uac12\uc774\ub2e4. \uc989, \ub9ac\ub354\uac00 \uc774\ubc88\uc5d0 \ubcf4\ub0b4\ub824\ub294 \uc0c8\ub85c\uc6b4 \ub85c\uadf8 \ud56d\ubaa9\ub4e4 \ubc14\ub85c \uc774\uc804 \ub85c\uadf8 \ud56d\ubaa9\uc758 \uc778\ub371\uc2a4\uc774\uba70 \ub9ac\ub354\ub294 \uc774 \uc9c0\uc810\uae4c\uc9c0 \ud314\ub85c\uc6cc\uc758 \ub85c\uadf8\uac00 \uc790\uc2e0\uacfc \uc77c\uce58\ud560 \uac83\uc774\ub77c\uace0 \uae30\ub300\ud55c\ub2e4. \uc774\ud6c4 \uc0c8\ub85c\uc6b4 \ub85c\uadf8\uac00 \ucd94\uac00\ub420 \ub54c \ud314\ub85c\uc6cc\ub4e4\uc740 `prevLogIndex`\ub97c \uc804\ub2ec \ubc1b\uc544\uc57c\ub9cc \ud314\ub85c\uc6cc\ub4e4\uc740 \uc790\uc2e0\uc758 \ud604\uc7ac \ub85c\uadf8 \uc778\ub371\uc2a4\uac00 \ub9ac\ub354\uc640 \uc77c\uce58\ud558\ub294\uc9c0 \uc54c \uc218 \uc788\uace0 `prevLogIndex == \ud604\uc7ac \uc778\ub371\uc2a4` \uc774\uba70 term\uae4c\uc9c0 \uc77c\uce58\ud560 \ub54c WAL\uc5d0 Log Entry\ub97c Append \ud55c\ub2e4.\\n- **\ub9cc\uc57d, \ubd88\uc77c\uce58 \ud55c\ub2e4\uba74?**\\n    - \ub450 \uac00\uc9c0 \ucf00\uc774\uc2a4\uac00 \uc788\uc744 \uc218 \uc788\ub294\ub370 \ud314\ub85c\uc6cc\uc758 \ud604\uc7ac \uc778\ub371\uc2a4\uac00 \ub354 \uc791\uc740 \uacbd\uc6b0: \uc774 \uacbd\uc6b0\ub294 \ub2e8\uc21c\ud788 reject \ud558\ub294\ub370 \ub9ac\ub354\ub294 reject\ub97c \uc218\uc2e0\ud558\uba74 preLogIndex\ub97c -1 \ud574\uc11c \ub2e4\uc2dc append \uc694\uccad\uc744 \ubcf4\ub0b8\ub2e4.\\n    - \ud314\ub85c\uc6cc\uc758 \uc778\ub371\uc2a4\uac00 \ub354 \ud070 \uacbd\uc6b0: \uc774 \uacbd\uc6b0\ub294 `prevLogTerm`\uc774 \uc911\uc694\ud55c \uc5ed\ud560\uc744\ud55c\ub2e4. \uc774 \uac12\uc744 \ud1b5\ud574 \ud604\uc7ac \ub9ac\ub354\uc758 term\uc744 \uc54c \uc218 \uc788\uace0 term\uc774 \ub2e4\ub974\ub2e4\uba74 term \uc77c\uce58\ud654 \uc2dc\ud0a4\uace0 \uc0c8\ub86d\uac8c log\ub4e4\uc744 Fallow\ud55c\ub2e4.\\n\\n> **prevLogIndex\uc640\xa0prevLogTerm: \ub85c\uadf8 \uc77c\uce58\uc131\uc758 \ud575\uc2ec**\\n> \\n\\nprevLogIndex\uc640\xa0prevLogTerm\uc740 Raft\uc5d0\uc11c\xa0\ub9ac\ub354\uac00 \ud314\ub85c\uc6cc\uc5d0\uac8c \ub85c\uadf8\ub97c \ubcf5\uc81c\ud560 \ub54c, \ud314\ub85c\uc6cc\uc758 \ub85c\uadf8\uac00 \ub9ac\ub354\uc758 \ub85c\uadf8\uc640 \uc77c\uad00\ub41c \uc0c1\ud0dc\ub97c \uc720\uc9c0\ud558\ub3c4\ub85d \ubcf4\uc7a5\ud558\ub294 \ub9e4\uc6b0 \uc911\uc694\ud55c \ud544\ub4dc\uc785\ub2c8\ub2e4. \uc774 \ub450 \ud544\ub4dc\ub294 \ud56d\uc0c1\xa0AppendEntries RPC\xa0\uba54\uc2dc\uc9c0\uc5d0 \ud568\uaed8\xa0\ud3ec\ud568\ub418\uc5b4 \uc0ac\uc6a9\ub41c\ub2e4.\\n\\n> **\ud314\ub85c\uc6cc\uc758 \ub85c\uadf8 \ucd94\uac00\xa0\uacfc\uc815 \ubc0f \uc77c\uce58\uc131 \uac80\uc99d**\\n> \\n1. **1\ub2e8\uacc4:\xa0prevLogIndex\uc640\xa0prevLogTerm\xa0\uc77c\uce58 \ud655\uc778** \\n    - \ud314\ub85c\uc6cc\ub294 \uc790\uc2e0\uc758 \ub85c\uceec \ub85c\uadf8\uc5d0\uc11c\xa0prevLogIndex\uc5d0 \ud574\ub2f9\ud558\ub294 \uc704\uce58\ub97c \ud655\uc778\ud55c\ub2e4.\\n    - **\ub9cc\uc57d \ub2e4\uc74c \uc911\xa0\ud558\ub098\ub77c\ub3c4 \ud574\ub2f9\ud558\uba74 RPC\ub97c \uac70\uc808(reject)\ud558\uace0 \ub9ac\ub354\uc5d0\uac8c \uc2e4\ud328\ub97c \uc751\ub2f5\ud55c\ub2e4.**\\n        - \ud314\ub85c\uc6cc\uc758 \ub85c\uadf8\uc5d0\xa0prevLogIndex\uc5d0 \ud574\ub2f9\ud558\ub294 \ub85c\uadf8 \ud56d\ubaa9\uc774 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294 \uacbd\uc6b0.\\n        - prevLogIndex\uc5d0 \ub85c\uadf8 \ud56d\ubaa9\uc740 \uc874\uc7ac\ud558\uc9c0\ub9cc, \ud574\ub2f9 \ud56d\ubaa9\uc758 \uc784\uae30 \ubc88\ud638\uac00 RPC\ub85c \uc804\ub2ec\ubc1b\uc740\xa0prevLogTerm\uacfc \uc77c\uce58\ud558\uc9c0 \uc54a\ub294 \uacbd\uc6b0.\\n    - \uc774 \uac80\uc0ac\ub97c \ud1b5\uacfc\ud558\uc9c0 \ubabb\ud558\uba74, \ub9ac\ub354\ub294 \ud574\ub2f9 \ud314\ub85c\uc6cc\uc758\xa0nextIndex\ub97c 1 \uac10\uc18c\uc2dc\ucf1c \ub2e4\uc74c\ubc88\xa0AppendEntries RPC\uc5d0\uc11c \ub354\xa0\uc774\uc804 \ub85c\uadf8\ubd80\ud130 \ub3d9\uae30\ud654\ub97c \uc2dc\ub3c4\ud55c\ub2e4.\\n2. **2\ub2e8\uacc4: \uae30\uc874 \ub85c\uadf8 \ucda9\ub3cc \ud574\uacb0 \ubc0f \uc0c8\xa0\ub85c\uadf8 \ucd94\uac00 (1\ub2e8\uacc4 \ud1b5\uacfc \uc2dc)**\\n    - \ub9cc\uc57d 1\ub2e8\uacc4 \uac80\uc0ac\ub97c \ud1b5\uacfc\ud588\ub2e4\uba74\xa0(\uc989, \ud314\ub85c\uc6cc\uc758 \ub85c\uadf8\uac00\xa0prevLogIndex\uae4c\uc9c0\ub294 \ub9ac\ub354\uc758 \ub85c\uadf8\uc640 \uc77c\uce58\ud568\uc774 \ud655\uc778\ub418\uc5c8\ub2e4\uba74), \ud314\ub85c\uc6cc\ub294 \ub2e4\uc74c\uc744 \uc9c4\ud589\ud55c\ub2e4.\\n    - RPC\uc5d0 \ud3ec\ud568\ub41c \uc0c8\ub85c\uc6b4 \ub85c\uadf8 \ud56d\ubaa9\ub4e4(entries[])\uacfc \uc790\uc2e0\uc758 \ub85c\uceec \ub85c\uadf8\ub97c \ube44\uad50\ud569\ub2c8\ub2e4. \ub9cc\uc57d \uc0c8\ub85c\uc6b4 \ub85c\uadf8 \ud56d\ubaa9\uacfc \ub3d9\uc77c\ud55c \uc778\ub371\uc2a4\ub97c\xa0\uac00\uc9c0\uc9c0\ub9cc \uc784\uae30 \ubc88\ud638\uac00 \ub2e4\ub978 \uae30\uc874 \ub85c\uadf8 \ud56d\ubaa9\uc774 \uc788\ub2e4\uba74 (\uc989, \ucda9\ub3cc\uc774 \ubc1c\uc0dd\ud558\uba74),\xa0**\ud574\ub2f9 \uae30\uc874 \ub85c\uadf8 \ud56d\ubaa9 \ubc0f \uadf8 \uc774\ud6c4\uc758 \ubaa8\ub4e0 \ub85c\uadf8 \ud56d\ubaa9\ub4e4\uc744 \uc790\uc2e0\uc758 \ub85c\uadf8\uc5d0\uc11c \uc0ad\uc81c\ud55c\ub2e4.**\xa0(\ub9ac\ub354\uc758 \ub85c\uadf8\uac00 \ud56d\uc0c1\xa0\uc6b0\uc120\uad8c\uc744 \uac00\uc9d1\ub2c8\ub2e4.)\\n    - \uadf8 \ud6c4, RPC\uc758\xa0entries[]\uc5d0 \ud3ec\ud568\ub41c, \uc544\uc9c1 \uc790\uc2e0\uc758\xa0\ub85c\uadf8\uc5d0 \uc5c6\ub294 \uc0c8\ub85c\uc6b4 \ub85c\uadf8 \ud56d\ubaa9\ub4e4\uc744 \uc21c\uc11c\ub300\ub85c \uc790\uc2e0\uc758 WAL\uc5d0 \ucd94\uac00(append)\ud55c\ub2e4.\\n    - \uc131\uacf5\uc801\uc73c\ub85c \ub85c\uadf8\ub97c \ucd94\uac00\ud55c \ud6c4 \ub9ac\ub354\uc5d0\uac8c \uc131\uacf5 \uc751\ub2f5\uc744 \ubcf4\ub0b8\ub2e4.\\n\\n---\\n\\n## \uc5b4\ub5bb\uac8c \uc774\ub807\uac8c \uc911\uc694\ud55c ETCD\uc758 \uc548\uc815\uc131\uc744 \ubcf4\uc7a5\ud560 \uc218 \uc788\uc744\uae4c? - Quorum(\uc815\uc871\uc218)\uc774\ub780 \ubb58\uae4c?\\n\\netcd\uc640 \uac19\uc740 \ubd84\uc0b0 \ud569\uc758 \uc2dc\uc2a4\ud15c\uc5d0\uc11c Quorum(\uc815\uc871\uc218)\ub294 **\ub370\uc774\ud130\uc758 \uc77c\uad00\uc131\uacfc \uc2dc\uc2a4\ud15c\uc758 \uc7a5\uc560 \ud5c8\uc6a9\uc131(Fault Tolerance)\uc744 \ubcf4\uc7a5\ud558\ub294 \ub370 \ud575\uc2ec \uc5ed\ud560\uc744 \ud55c\ub2e4.** \uc815\uc871\uc218 \uacc4\uc0b0\uc744 \ud1b5\ud574 \ucd5c\ub300 \uc7a5\uc560 \ud5c8\uc6a9 \ub178\ub4dc \uc218\uac00 \uacb0\uc815 \ub418\ub294\ub370 \uacf5\uc2dd\uc740 \ub2e4\uc74c\uacfc \uac19\ub2e4.\\n\\n$$\\nN/2 + 1 \\n$$\\n\\n**\ub0b4\uacb0\ud568\uc131 (Fault Tolerance):**\xa0N\uac1c\uc758 \ub178\ub4dc\ub85c \uad6c\uc131\ub41c \ud074\ub7ec\uc2a4\ud130\uc5d0\uc11c\xa0(N-1)/2\uac1c\uc758 \ub178\ub4dc\uae4c\uc9c0 \uc7a5\uc560\uac00 \ubc1c\uc0dd\ud574\ub3c4, \ub098\uba38\uc9c0\xa0N/2 + 1\uac1c\uc758\xa0\ub178\ub4dc\uac00 \uc815\uc871\uc218\ub97c \uc774\ub8f0 \uc218 \uc788\uc73c\ubbc0\ub85c \uc2dc\uc2a4\ud15c\uc740 \uacc4\uc18d \uc815\uc0c1\uc801\uc73c\ub85c \uc791\ub3d9\ud560 \uc218 \uc788\ub2e4.\\n\\n- 3\uac1c \ub178\ub4dc: (3-1)/2 = 1\uac1c \ub178\ub4dc \uc7a5\uc560 \ud5c8\uc6a9\\n- 5\uac1c \ub178\ub4dc: (5-1)/2 = 2\uac1c \ub178\ub4dc \uc7a5\uc560 \ud5c8\uc6a9\\n- 7\uac1c \ub178\ub4dc: (7-1)/2 = 3\uac1c \ub178\ub4dc \uc7a5\uc560 \ud5c8\uc6a9\\n\\n> \ub9cc\uc57d, \ubaa8\ub4e0 \uc815\uc871\uc218 \uc774\uc0c1\uc758 \ub178\ub4dc\ub4e4\uc774 \uc9c0\uc5f0\uc774 \uc788\uac70\ub098 \uc751\ub2f5\uc774 \uc5c6\ub2e4\uba74? \uc5b4\ub5bb\uac8c \ub420\uae4c? \uc7ac\uc2dc\ub3c4\ub97c \ubb34\ud55c\ud788 \ud558\ub098? \uacb0\uad6d \ucd5c\uc885 \uc2e4\ud328\ub41c\ub2e4\uba74? \uc2e4\ud328\ud588\uc744 \ub54c \uacfc\ubc18\uc218\ub97c \ucc44\uc6b0\uc9c0 \ubabb\ud55c\ub2e4\uba74?\\n> \\n\\n**RSM \ud2b9\uc131 \uc0c1 \uc21c\ucc28\uc801\uc73c\ub85c \ucc98\ub9ac\ub418\uc5b4\uc57c \ud558\uae30 \ub54c\ubb38\uc5d0 \uc9c0\uc5f0 or \uc7a5\uc560\uac00 \ubc1c\uc0dd\ud558\uac8c \ub41c\ub2e4.** \ucd5c\uc545\uc758 \uacbd\uc6b0\ub97c \uace0\ub824\ud558\uba74 \uc815\uc871\uc218 \uc774\uc0c1\uc758 \ub178\ub4dc\ub4e4\uc774 Log Append\ub97c \ud558\uc9c0 \ubabb\ud574 AppendRPC call\uc758 \uc751\ub2f5\uc744 \ubc1b\uc9c0 \ubabb\ud55c\ub2e4\uba74 \ub354 \uc774\uc0c1\uc758 Write \uc791\uc5c5\uc740 \ubd88\uac00\ub2a5\ud574\uc9c0\uace0 \ud6c4\uc18d Log\ub4e4 \ub610\ud55c RSM \ud2b9\uc131 \uc0c1 \uc21c\ucc28\uc801\uc73c\ub85c \ucc98\ub9ac\ub418\uc5b4\uc57c \ud558\uae30 \ub54c\ubb38\uc5d0 \uc9c0\uc5f0 or \uc7a5\uc560\uac00 \ubc1c\uc0dd\ud558\uac8c \ub41c\ub2e4. \\n\\n**\ub9cc\uc57d, \uc815\uc871\uc218\ub9cc\ud07c\uc740 Replication \ub41c \uacbd\uc6b0\ub77c\uba74,** \uc815\uc0c1\uc801\uc73c\ub85c \uc11c\ube44\uc2a4\ub41c\ub2e4. \ud558\uc9c0\ub9cc \uc751\ub2f5\ud558\uc9c0 \uc54a\uc740 \ub178\ub4dc\ub294 \ub4a4\uccd0\uc9c4 \uc0c1\ud0dc\uac00 \ub418\ub294\ub370 \uc774\ud6c4 \uc815\uc0c1\uc801\uc73c\ub85c Join\ub418\uba74 \ub2e4\uc2dc Leader\uc758 \ub85c\uadf8\ub85c \ub3d9\uae30\ud654\ub41c\ub2e4."},{"id":"\ucfe0\ubc84\ub124\ud2f0\uc2a4\uc5d0\uc11c \uc548\uc815\uc801\uc778 \uc11c\ube44\uc2a4 \uc6b4\uc601\uc744 \uc704\ud55c 3\uac00\uc9c0 \uaddc\uce59\ub4e4","metadata":{"permalink":"/blog/\ucfe0\ubc84\ub124\ud2f0\uc2a4\uc5d0\uc11c \uc548\uc815\uc801\uc778 \uc11c\ube44\uc2a4 \uc6b4\uc601\uc744 \uc704\ud55c 3\uac00\uc9c0 \uaddc\uce59\ub4e4","source":"@site/blog/\uc548\uc815\uc801\uc73c\ub85c Pod\uc744 \uc6b4\uc601\ud558\uae30 \uc704\ud55c \uaddc\uce59\ub4e4.mdx","title":"\ucfe0\ubc84\ub124\ud2f0\uc2a4\uc5d0\uc11c \uc548\uc815\uc801\uc778 \uc11c\ube44\uc2a4 \uc6b4\uc601\uc744 \uc704\ud55c 3\uac00\uc9c0 \uaddc\uce59","description":"\ube44\uc988\ub2c8\uc2a4\ub97c \uc6b4\uc601\ud558\ub294 \uc5d4\uc9c0\ub2c8\uc5b4 \uc785\uc7a5\uc5d0\uc11c \uac00\uc7a5 \uc704\ud5d8\ud55c \uac83\uc740 \uc11c\ube44\uc2a4 \uc7a5\uc560\ub85c \uc0ac\uc6a9\uc790 \uacbd\ud5d8\uc744 \uc800\ud574\uc2dc\ucf1c \uc11c\ube44\uc2a4\uc758 \uc2e0\ub8b0\ub3c4\ub97c \ub5a8\uc5b4\ub728\ub9ac\ub294 \uac83\uc774\ub77c \uc0dd\uac01\ud55c\ub2e4. \ub530\ub77c\uc11c \uc6b0\ub9ac\uc758 \uc5ed\ud560\uc740 \uc7a5\uc560\uc640 \ub2e4\uc6b4\ud0c0\uc784\uc744 \ucd5c\uc18c\ud55c\uc73c\ub85c \uc904\uc774\ub294 \uac83\uc774 \uc6b0\ub9ac\uc758 \uc5ed\ud560\uc774\uc790 \ucc45\uc784\uc774\ub77c \uc0dd\uac01\ud55c\ub2e4.","date":"2025-05-06T04:00:29.000Z","tags":[{"inline":false,"label":"Kubernetes","permalink":"/blog/tags/kubernetes","description":"Kubernetes tag description"}],"readingTime":10.23,"hasTruncateMarker":true,"authors":[{"name":"Changhwan","title":"\ucee8\ud14c\uc774\ub108\uc640 \ud074\ub77c\uc6b0\ub4dc \ub124\uc774\ud2f0\ube0c \uae30\uc220\uc5d0 \uad00\uc2ec\uc774 \ub9ce\uc73c\uba70, \ud6a8\uc728\uc801\uc774\uba74\uc11c \uc548\uc815\uc801\uc778 \uc11c\ube44\uc2a4\ub97c \ub9cc\ub4e4\uace0\uc790 \ub178\ub825\ud569\ub2c8\ub2e4.","url":"https://github.com/changhwanK","page":null,"imageURL":"/img/insta.jpg","key":"changhwan"}],"frontMatter":{"slug":"\ucfe0\ubc84\ub124\ud2f0\uc2a4\uc5d0\uc11c \uc548\uc815\uc801\uc778 \uc11c\ube44\uc2a4 \uc6b4\uc601\uc744 \uc704\ud55c 3\uac00\uc9c0 \uaddc\uce59\ub4e4","title":"\ucfe0\ubc84\ub124\ud2f0\uc2a4\uc5d0\uc11c \uc548\uc815\uc801\uc778 \uc11c\ube44\uc2a4 \uc6b4\uc601\uc744 \uc704\ud55c 3\uac00\uc9c0 \uaddc\uce59","authors":["changhwan"],"tags":["kubernetes"],"comments":true},"unlisted":false,"prevItem":{"title":"Inside etcd - \uc65c K8s\ub294 etcd\ub97c \ubc31\ud0b9 \uc2a4\ud1a0\ub9ac\uc9c0\ub85c \uc120\ud0dd\ud588\uc744\uae4c?","permalink":"/blog/2025-05-21-Inside etcd - \uc65c K8s\ub294 etcd\ub97c \ubc31\ud0b9 \uc2a4\ud1a0\ub9ac\uc9c0\ub85c \uc120\ud0dd\ud588\uc744\uae4c"}},"content":"**\ube44\uc988\ub2c8\uc2a4\ub97c \uc6b4\uc601\ud558\ub294 \uc5d4\uc9c0\ub2c8\uc5b4 \uc785\uc7a5\uc5d0\uc11c \uac00\uc7a5 \uc704\ud5d8\ud55c \uac83\uc740 \uc11c\ube44\uc2a4 \uc7a5\uc560\ub85c \uc0ac\uc6a9\uc790 \uacbd\ud5d8\uc744 \uc800\ud574\uc2dc\ucf1c \uc11c\ube44\uc2a4\uc758 \uc2e0\ub8b0\ub3c4\ub97c \ub5a8\uc5b4\ub728\ub9ac\ub294 \uac83\uc774\ub77c \uc0dd\uac01\ud55c\ub2e4.** \ub530\ub77c\uc11c \uc6b0\ub9ac\uc758 \uc5ed\ud560\uc740 **\uc7a5\uc560\uc640 \ub2e4\uc6b4\ud0c0\uc784\uc744 \ucd5c\uc18c\ud55c\uc73c\ub85c \uc904\uc774\ub294 \uac83\uc774 \uc6b0\ub9ac\uc758 \uc5ed\ud560\uc774\uc790 \ucc45\uc784\uc774\ub77c \uc0dd\uac01\ud55c\ub2e4.**\\n\\n\ub9cc\uc57d, \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub97c \uc0ac\uc6a9\ud574 \uc11c\ube44\uc2a4\ub97c \uc6b4\uc601\ud55c\ub2e4\uba74 \ucfe0\ubc84\ub124\ud2f0\uc2a4\ub294 \uc774\ub7f0 \ubd80\ubd84\uc5d0 \uc788\uc5b4 \uac15\ub825\ud55c \uae30\ub2a5\ub4e4\uc744 \uc81c\uacf5\ud55c\ub2e4.\\n\\n\x3c!-- truncate --\x3e\\n\\n---\\n\\n## 1.  Deployment \ud65c\uc6a9\ud558\uae30\\n\\n> \ucfe0\ubc84\ub124\ud2f0\uc2a4 \ud658\uacbd\uc5d0\uc11c \uc11c\ube44\uc2a4\ub97c \uc6b4\uc601\ud55c\ub2e4\uba74 \uc548\uc815\uc131\uc744 \ub192\uc77c \uc218 \uc788\ub294 \uba54\ucee4\ub2c8\uc998\uc744 \uc81c\uacf5\ud55c\ub2e4. \ub530\ub77c\uc11c \ucfe0\ubc84\ub124\ud2f0\uc2a4 \ud658\uacbd\uc5d0\uc11c\ub294 \uc5b4\ub835\uc9c0 \uc54a\uac8c \uc548\uc815\uc131\uc744 \ub192\uc77c \uc218 \uc788\ub294\ub370 \uadf8 \uc2dc\uc791\uc744 \uc704\ud55c \uccab \ubc88\uc9f8\ub294 `Deployment`\ub77c\ub294 Workload\ub97c \ud65c\uc6a9\ud558\ub294 \uac83\uc774\ub2e4.\\n\\n\ucfe0\ubc84\ub124\ud2f0\uc2a4\uc758 Deployment\ub294 \uc560\ud50c\ub9ac\ucf00\uc774\uc158\uc758 \uc120\uc5b8\uc801 \uc5c5\ub370\uc774\ud2b8\uc640 \ub864\ubc31\uc744 \uad00\ub9ac\ud558\ub294 \ubc29\ubc95\uc744 \uc81c\uacf5\ud558\ub294 API \uc624\ube0c\uc81d\ud2b8\uc774\uba70 \ub2e4\uc74c\uacfc \uac19\uc740 \ud2b9\uc9d5\ub4e4\uc744 \uac00\uc9c4\ub2e4.\\n\\n1.  **\ud30c\ub4dc \uad00\ub9ac \ubc0f \uc5c5\ub370\uc774\ud2b8:** Deployment\ub294 ReplicaSet(\ub808\ud50c\ub9ac\uce74\uc14b)\uc744 \uc0ac\uc6a9\ud574 \uc9c0\uc815\ub41c \uc218\uc758 \ud30c\ub4dc \ubcf5\uc81c\ubcf8\uc744 \uc720\uc9c0 \uad00\ub9ac\ud55c\ub2e4. \uc0ac\uc6a9\uc790\ub294 Deployment\ub97c \ud1b5\ud574 \uc560\ud50c\ub9ac\ucf00\uc774\uc158\uc744 \uc5c5\ub370\uc774\ud2b8\ud560 \ub54c \uc0c8\ub85c\uc6b4 \uc774\ubbf8\uc9c0\ub85c Pod\ub97c \uc548\uc804\ud558\uac8c Rollout \ud560 \uc218 \uc788\ub2e4.\\n2.  **\ub864\ubc31:** Deployment\ub294 \ubcc0\uacbd \uc0ac\ud56d\uc744 \uc27d\uac8c \ub418\ub3cc\ub9b4 \uc218 \uc788\ub3c4\ub85d \uc9c0\uc6d0\ud558\uc5ec, \uc0c8\ub85c\uc6b4 \uc5c5\ub370\uc774\ud2b8\uc5d0 \ubb38\uc81c\uac00 \uc788\uc744 \ub54c \uc774\uc804 Revision\uc73c\ub85c \ub864\ubc31\ud560 \uc218 \uc788\ub294 \uae30\ub2a5\uc744 \uc81c\uacf5\ud55c\ub2e4.\\n3.  **Probe**: Deployment\ub294 \uc5c5\ub370\uc774\ud2b8 \uc911\uc5d0 \ud30c\ub4dc\uc758 \uc0c1\ud0dc\ub97c \ubaa8\ub2c8\ud130\ub9c1\ud558\uace0, \uc815\ud574\uc9c4 \uae30\uc900\uc5d0 \ub9de\uc9c0 \uc54a\ub294 \uacbd\uc6b0 \uc7ac\uc2dc\uc791\uc2dc\ucf1c \ubb38\uc81c\ub97c \ud574\uacb0\ud560 \uc218 \uc788\ub3c4\ub85d \ud55c\ub2e4.\\n\\nDeployment\uc758 \uc774\ub7ec\ud55c \ud2b9\uc9d5\ub4e4\uc740 Pod\uc758 \uc548\uc815\uc131\uc744 \ub192\uc774\ub294 \ub370 \ud06c\uac8c \uae30\uc5ec\ud55c\ub2e4. \ud2b9\ud788 Probe \uba54\ucee4\ub2c8\uc998\uacfc Replica\ub294 \uc548\uc815\uc131\uc758 \ud575\uc2ec\uc774\ub77c \ubcfc \uc218 \uc788\uc73c\uba70 Rollback\uc744 \ud1b5\ud574 \ubb38\uc81c\ub97c \ube60\ub974\uac8c \uc6d0\ubcf5\uc2dc\ud0a4\ub294 \uac83\uc774 \uac00\ub2a5\ud558\ub2e4.\\n\\nDeployment\ub97c \uc0ac\uc6a9\ud574 \uc11c\ube44\uc2a4\ub97c \uc6b4\uc601\ud560 \ub54c\ub294 Replica Count\ub97c 2\uac1c \uc774\uc0c1\uc73c\ub85c \uace0\uc815\ud558\ub294 \uac83\uc744 \ucd94\ucc9c\ud558\uba70, \ud558\ub098\uc758 Pod\uac00 Down \ub418\uc5b4\ub3c4 Replica\ub97c \ud1b5\ud574 \ud2b8\ub798\ud53d\uc744 \uc9c0\uc18d\uc801\uc73c\ub85c \ucc98\ub9ac \uac00\ub2a5\ud558\ub2e4.\\n\\n\ud558\uc9c0\ub9cc Replica \uc124\uc815\uc73c\ub85c\ub9cc \ubaa8\ub4e0 \ud2b8\ub798\ud53d\uc744 \ucc98\ub9ac\ud560 \uc218 \uc788\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4. Kubernetes \uc785\uc7a5\uc5d0\uc11c Pod\uc758 \uc0c1\ud0dc\uac00 \uc815\uc0c1\uc774\uc9c0\ub9cc \uc560\ud50c\ub9ac\ucf00\uc774\uc158\uc774 \ud2b8\ub798\ud53d\uc744 \ucc98\ub9ac\ud560 \uc218 \uc5c6\ub294 \uc0c1\ud0dc\uc77c \uc218 \uc788\uae30 \ub54c\ubb38\uc774\ub2e4. \ub530\ub77c\uc11c \ud2b8\ub798\ud53d\uc744 \ucc98\ub9ac\ud560 \uc218 \uc5c6\ub294 Pod\ub85c \ud2b8\ub798\ud53d\uc744 \ubcf4\ub0b4\uc9c0 \uc54a\ub294 \uba54\ucee4\ub2c8\uc998\uc774 \ud544\uc694\ud55c\ub370 \uc774\ub294 **Probe**\ub97c \ud1b5\ud574 \ub2ec\uc131\ud560 \uc218 \uc788\ub2e4.\\n\\n**Probe**\uc5d0\ub294 \ub2e4\uc74c\uacfc \uac19\uc740 \uc138 \uac00\uc9c0 \uc720\ud615\uc774 \uc788\ub2e4.\\n\\n*   **`startupProbe`**: \ucee8\ud14c\uc774\ub108 \ub0b4\uc758 \uc560\ud50c\ub9ac\ucf00\uc774\uc158\uc774 \uc2dc\uc791\ub418\uc5c8\ub294\uc9c0 \uc5ec\ubd80\ub97c \ub098\ud0c0\ub0b8\ub2e4. startupProbe\uac00 \uc81c\uacf5\ub418\uba74 \uc131\uacf5\ud560 \ub54c\uae4c\uc9c0 \ub2e4\ub978 \ubaa8\ub4e0 Probe\ub294 \ube44\ud65c\uc131\ud654\ub41c\ub2e4. \uc560\ud50c\ub9ac\ucf00\uc774\uc158 \uc2dc\uc791\uc774 \uc624\ub798 \uac78\ub9ac\ub294 \uacbd\uc6b0 \uc720\uc6a9\ud558\ub2e4.\\n*   **`livenessProbe`**: \ucee8\ud14c\uc774\ub108\uac00 \uc2e4\ud589 \uc911\uc778\uc9c0 \uc5ec\ubd80\ub97c \ub098\ud0c0\ub0b8\ub2e4. livenessProbe\uac00 \uc2e4\ud328\ud558\uba74 kubelet\uc740 \ucee8\ud14c\uc774\ub108\ub97c \uc8fd\uc774\uace0, \ucee8\ud14c\uc774\ub108\ub294 \uc7ac\uc2dc\uc791 \uc815\ucc45\uc5d0 \ub530\ub77c \ucc98\ub9ac\ub41c\ub2e4. \uc608\ub97c \ub4e4\uc5b4, \uc560\ud50c\ub9ac\ucf00\uc774\uc158\uc774 \ub370\ub4dc\ub77d \uc0c1\ud0dc\uc5d0 \ube60\uc838 \uc751\ub2f5\ud558\uc9c0 \uc54a\uc744 \ub54c \uc774\ub97c \uac10\uc9c0\ud558\uace0 \uc7ac\uc2dc\uc791\ud558\uc5ec \ubb38\uc81c\ub97c \ud574\uacb0\ud560 \uc218 \uc788\ub2e4.\\n*   **`readinessProbe`**: \ucee8\ud14c\uc774\ub108\uac00 \uc694\uccad\uc744 \ucc98\ub9ac\ud560 \uc900\ube44\uac00 \ub418\uc5c8\ub294\uc9c0 \uc5ec\ubd80\ub97c \ub098\ud0c0\ub0b8\ub2e4. readinessProbe\uac00 \uc2e4\ud328\ud558\uba74 \uc5d4\ub4dc\ud3ec\uc778\ud2b8 \ucee8\ud2b8\ub864\ub7ec\ub294 \uc774 Pod\uc758 IP \uc8fc\uc18c\ub97c \ubaa8\ub4e0 \uc11c\ube44\uc2a4\uc758 \uc5d4\ub4dc\ud3ec\uc778\ud2b8\uc5d0\uc11c \uc81c\uac70\ud55c\ub2e4. \uc989, \uc900\ube44\ub418\uc9c0 \uc54a\uc740 Pod\ub85c\ub294 \ud2b8\ub798\ud53d\uc774 \uc804\ub2ec\ub418\uc9c0 \uc54a\ub294\ub2e4.\\n\\n\uc774\ub7ec\ud55c Probe\ub4e4\uc744 \uc801\uc808\ud788 \ud65c\uc6a9\ud558\uba74 Kubernetes\ub294 Pod\uc758 \uc0c1\ud0dc\ub97c \ub354 \uc815\ud655\ud558\uac8c \ud310\ub2e8\ud560 \uc218 \uc788\uac8c \ub418\uace0, Healthy\ud55c Pod\ub85c\ub9cc \ud2b8\ub798\ud53d\uc744 \ubcf4\ub0b4\uc5b4 \uc11c\ube44\uc2a4\ub97c \uc548\uc815\uc801\uc73c\ub85c \uc6b4\uc601\ud560 \uc218 \uc788\ub2e4. (\uac01 Probe\uc758 \uc0c1\uc138 \uc124\uc815 \ubc0f \uace0\uae09 \ud65c\uc6a9\ubc95\uc740 \ucd94\ud6c4 \ub2e4\ub978 \uae00\uc5d0\uc11c \ub2e4\ub8e8\ub3c4\ub85d \ud558\uaca0\ub2e4.)\\n\\n---\\n\\n## 2. \ubd84\uc0b0\ubc30\uce58 (\ud1a0\ud3f4\ub85c\uc9c0 \ubd84\uc0b0)\\n\\n<div className=\\"prompt-info\\">\\n> \uc11c\ube44\uc2a4\ub97c \uc6b4\uc601\ud560 \ub54c Node\ub4e4\uc740 Availability Zone\uc744 \ub2e4\ub974\uac8c \uc124\uc815\ud55c\ub2e4. \uc774\ub7ec\ud55c \uba54\ucee4\ub2c8\uc998\uc740 \ud558\ub098\uc758 IDC\uc5d0 \ubb38\uc81c\uac00 \uc0dd\uaca8\ub3c4 \uc804\uccb4 \uc11c\ube44\uc2a4\uc5d0 \uc601\ud5a5 \uac00\ub294 \uac83\uc744 \ub9c9\uae30 \uc704\ud55c \uac83\uc778\ub370 Pod\ub3c4 \ub3d9\uc77c\ud558\ub2e4. Pod \ub610\ud55c Node \ubcc4\ub85c \ubd84\uc0b0\ubc30\uce58\ud558\uc5ec \ud558\ub098\uc758 Node\uac00 \uc8fd\uc5c8\uc744 \ub54c \ubaa8\ub4e0 Pod\uc774 \uc8fd\uc9c0 \uc54a\ub3c4\ub85d \ud574\uc57c \ud55c\ub2e4.\\n</div>\\n\\n\uae30\ubcf8 \uc124\uc815\uc758 Deployment\ub97c \ud1b5\ud574 Replica\ub97c \uc6b4\uc601\ud55c\ub2e4\uba74 Node\uc5d0\ub294 \uac19\uc740 Pod\uac00 \uc5ec\ub7ec \uac1c \ub3d9\uc791\ud560 \uc218 \uc788\ub2e4. \uc6b4\uc774 \uc88b\uc9c0 \uc54a\ub2e4\uba74 \ud558\ub098\uc758 Node\uc5d0 Replica\ub4e4\uc774 \ubaa8\ub450 \ubd84\ud3ec\ub420 \uc218 \uc788\ub294\ub370 \uc774\ub54c Node\uac00 \uc911\ub2e8\ub41c\ub2e4\uba74, \uc804\uccb4 \uc11c\ube44\uc2a4\uac00 Down\ub41c \uac83\uc774 \ub41c\ub2e4. \ub530\ub77c\uc11c \ud558\ub098\uc758 Node\uc5d0 \ubaa8\ub4e0 Replica\ub4e4\uc774 \ubd84\ud3ec\ub418\uc9c0 \uc54a\ub3c4\ub85d \ubd84\uc0b0 \ubc30\uce58\ud558\ub294 \uac83\uc774 \uc911\uc694\ud558\ub2e4. \ubd84\uc0b0\ubc30\uce58\ub97c \uc704\ud55c \uba54\ucee4\ub2c8\uc998\uc740 \ud06c\uac8c \ub450 \uac00\uc9c0\uc774\ub2e4.\\n\\n1.  **Pod Anti Affinity**\\n2.  **topologySpreadConstraints**\\n\\n**Pod Anti Affinity:**\\n\\n-   **Pod AntiAffinity\ub294 \ud2b9\uc815 Pod\ub4e4\uc774 \uc11c\ub85c \ub2e4\ub978 \ub178\ub4dc\uc5d0 \ubc30\uce58\ub418\ub3c4\ub85d \ud558\ub294 \uc124\uc815\uc774\ub2e4.** \uc608\ub97c \ub4e4\uc5b4, \ub192\uc740 \uac00\uc6a9\uc131\uc744 \uc704\ud574 \uac19\uc740 \uc11c\ube44\uc2a4\uc758 \uc5ec\ub7ec \uc778\uc2a4\ud134\uc2a4\uac00 \uac19\uc740 \ub178\ub4dc\uc5d0 \ubaa8\ub450 \uc704\uce58\ud558\uc9c0 \uc54a\ub3c4\ub85d \ud560 \uc218 \uc788\ub2e4.\\n-   AntiAffinity\ub294 \uc8fc\ub85c Label Selector\ub97c \uc0ac\uc6a9\ud574 \ud2b9\uc815 \ub808\uc774\ube14\uc744 \uac00\uc9c4 Pod\ub4e4\uacfc\uc758 \uadfc\uc811\uc131\uc744 \uc81c\uc5b4\ud55c\ub2e4. \uc608\ub97c \ub4e4\uc5b4, \uac19\uc740 \uc560\ud50c\ub9ac\ucf00\uc774\uc158\uc758 \ub2e4\ub978 \uc778\uc2a4\ud134\uc2a4\uc640\ub294 \ub2e4\ub978 \ub178\ub4dc\uc5d0 \ubc30\uce58\ub418\uc5b4\uc57c \ud568\uc744 \uba85\uc2dc\ud560 \uc218 \uc788\ub2e4.\\n\\n```yaml\\n---\\napiVersion: apps/v1\\nkind: Deployment\\nspec:\\n  replicas: 2\\n  template:\\n    spec:\\n      containers:\\n      - name: my-container\\n        # application specific container configurations\\n        image: my-image\\n      affinity:\\n        podAntiAffinity:\\n          requiredDuringSchedulingIgnoredDuringExecution:\\n            - labelSelector:\\n                matchExpressions:\\n                  - key: \\"app\\"\\n                    operator: In\\n                    values:\\n                      - myapp\\n              topologyKey: \\"kubernetes.io/hostname\\"\\n```\\n\\n**topologySpreadConstraints:**\\n\\n-   `topologySpreadConstraints`\ub294 \ud074\ub7ec\uc2a4\ud130 \ub0b4\uc758 \ud2b9\uc815 \ud1a0\ud3f4\ub85c\uc9c0(\uc608: \ub178\ub4dc, \ub799, \uc874 \ub4f1)\uc5d0 \uac78\uccd0 Pod\ub4e4\uc774 \uade0\ub4f1\ud558\uac8c \ubd84\ud3ec\ub418\ub3c4\ub85d \ud558\ub294 \uc124\uc815\uc774\ub2e4. \uc774\ub294 \ud074\ub7ec\uc2a4\ud130\uc758 \ub9ac\uc18c\uc2a4 \uc0ac\uc6a9\ub960\uc744 \ucd5c\uc801\ud654\ud558\uace0, \ud2b9\uc815 \uc9c0\uc5ed\uc5d0 \uc11c\ube44\uc2a4 \uc911\ub2e8\uc774 \ubc1c\uc0dd\ud588\uc744 \ub54c \uc601\ud5a5\uc744 \ucd5c\uc18c\ud654\ud558\ub294 \ub370 \uc720\uc6a9\ud558\ub2e4.\\n-   \uc0ac\uc6a9\uc790\ub294 `maxSkew`, `topologyKey`, `whenUnsatisfiable` \uac19\uc740 \ud30c\ub77c\ubbf8\ud130\ub97c \uc124\uc815\ud574 \uc6d0\ud558\ub294 \ubd84\uc0b0 \uc815\ub3c4\uc640 \ud589\ub3d9\uc744 \uc815\uc758\ud560 \uc218 \uc788\ub2e4. \uc608\ub97c \ub4e4\uc5b4, `maxSkew: 1`\uc740 \uc9c0\uc815\ub41c \ud1a0\ud3f4\ub85c\uc9c0 \uacbd\uacc4 \ub0b4\uc5d0\uc11c \ubaa8\ub4e0 Pod\uc758 \uc218\uac00 \ud558\ub098 \uc774\uc0c1 \ucc28\uc774 \ub098\uc9c0 \uc54a\ub3c4\ub85d \ud55c\ub2e4\ub294 \uac83\uc744 \uc758\ubbf8\ud55c\ub2e4.\\n\\n```yaml\\n---\\napiVersion: apps/v1\\nkind: Deployment\\nspec:\\n  replicas: 2\\n  template:\\n    spec:\\n      topologySpreadConstraints:\\n        - maxSkew: 1\\n          topologyKey: \\"kubernetes.io/hostname\\"\\n          whenUnsatisfiable: DoNotSchedule\\n          labelSelector:\\n            matchLabels:\\n              app: myapp\\n      containers:\\n      - name: mycontainer\\n        # application specific container configurations\\n        image: my-image\\n```\\n\\n-   **topologyKey**: Pod\ub4e4\uc774 \ubd84\uc0b0\ub420 \uae30\uc900\uc774 \ub418\ub294 \ud1a0\ud3f4\ub85c\uc9c0 \ud0a4\ub97c \uc9c0\uc815\ud55c\ub2e4. \uc5ec\uae30\uc11c\ub294 `\\"kubernetes.io/hostname\\"`\uc744 \uc0ac\uc6a9\ud574 \uac01 Pod\uac00 \ub2e4\ub978 \ud638\uc2a4\ud2b8\uc5d0 \ubc30\uce58\ub418\ub3c4\ub85d \ud55c\ub2e4.\\n-   **whenUnsatisfiable**: \uc2a4\ucf00\uc904\ub9c1 \uc635\uc158\uc774 \ub9cc\uc871\ub418\uc9c0 \uc54a\uc744 \ub54c\uc758 \ud589\ub3d9\uc744 \uc9c0\uc815\ud55c\ub2e4. `DoNotSchedule`\uc740 \uc870\uac74\uc744 \ub9cc\uc871\ud558\ub294 \ub178\ub4dc\uac00 \uc5c6\uc744 \uacbd\uc6b0 \uc0c8\ub85c\uc6b4 Pod\ub97c \uc2a4\ucf00\uc904\ud558\uc9c0 \uc54a\ub294\ub2e4.\\n-   **labelSelector**: \uc774 \uc81c\uc57d\uc870\uac74\uc774 \uc801\uc6a9\ub420 Pod\ub4e4\uc758 Label Selector\uc774\ub2e4. \uc774 \uacbd\uc6b0 `app: myapp` \ub808\uc774\ube14\uc744 \uac00\uc9c4 Pod\ub4e4\uc774 \ub300\uc0c1\uc774\ub2e4.\\n\\n\uc815\ub9ac\ud558\uba74 `Pod AntiAffinity`\ub294 \uc8fc\ub85c \ub2e4\ub978 \ud2b9\uc815 Pod\uc640\uc758 \ubc30\uce58\ub97c \ud68c\ud53c\ud558\ub294 \ub370 \ucd08\uc810\uc744 \ub9de\ucd94\ub294 \ubc18\uba74, `topologySpreadConstraints`\ub294 \ud074\ub7ec\uc2a4\ud130 \uc804\ubc18\uc5d0 \uac78\uccd0 Pod\uc758 \uade0\ub4f1\ud55c \ubd84\ud3ec\ub97c \uc870\uc815\ud558\ub294 \ub370 \ub354 \uc801\ud569\ud558\ub2e4.\\n\\n---\\n\\n## 3. Graceful Shutdown\\n\\n<div className=\\"prompt-info\\">\\n> Graceful Shutdown \uc124\uc815\uc740 Pod\uac00 \uc2e4\ud589 \uc911\uc778 \uc791\uc5c5\uc744 \uc548\uc804\ud558\uac8c \uc885\ub8cc\ud55c \ud6c4, Pod\ub97c \uc885\ub8cc\uc2dc\ud0a4\ub294 \uac83\uc744 \uc758\ubbf8\ud55c\ub2e4. \ub9cc\uc57d Pod\uac00 \uc2e4\ud589 \uc911\uc778 \uc791\uc5c5\uc774 \uc548\uc804\ud558\uac8c \uc885\ub8cc\ub418\uc9c0 \uc54a\uace0 \uc885\ub8cc\ub420 \uacbd\uc6b0 \ub9ac\uc18c\uc2a4 \ub0ad\ube44(DB \ucee4\ub125\uc158 \ubc18\ub0a9\uc2e4\ud328)\uc640 \ub124\ud2b8\uc6cc\ud06c \uc785\uc7a5\uc5d0\uc11c\ub294 \uac11\uc790\uae30 \uc5f0\uacb0\uc774 \ub04a\uae30\ub294 \ud604\uc0c1\uacfc \uac19\uc740 \uc7a5\uc560\uac00 \ubc1c\uc0dd\ud55c\ub2e4.\\n</div>\\n\\nPod\uc758 Life Cycle\uc740 kubelet\uc774 \uad00\uc7a5\ud55c\ub2e4. kubelet\uc740 `SIGTERM` \uc2dc\uadf8\ub110\uc744 \ubcf4\ub0b4\uc5b4 Graceful \ud55c \uc885\ub8cc\ub97c \uc720\ub3c4\ud558\ub294\ub370 Pod\ub294 SIGTERM \uc2dc\uadf8\ub110\uc744 \ubc1b\uc73c\uba74 \ud504\ub85c\uc138\uc2a4\ub97c \uc815\ub9ac\ud558\uace0 \uc885\ub8cc\ud560 \uc900\ube44\ub97c \ud55c\ub2e4. \uadf8\ub7ec\ub098, \uc77c\ubd80 Pod\uc740 `SIGTERM` \uc2dc\uadf8\ub110\uc744 \ubb34\uc2dc\ud558\ub294 \uacbd\uc6b0\uac00 \uc788\ub294\ub370 \uc774 \uacbd\uc6b0 kubelet\uc740 `terminationGracePeriodSeconds` \uc5d0 \uc9c0\uc815\ub41c \uc2dc\uac04 \ub3d9\uc548 \ub300\uae30\ud558\uba70, \uc774 \uc2dc\uac04 \ub0b4\uc5d0 \ucee8\ud14c\uc774\ub108\uac00 \uc885\ub8cc\ub418\uc9c0 \uc54a\ub294\ub2e4\uba74 `SIGKILL` \uc2dc\uadf8\ub110\uc744 \ubcf4\ub0b4\uc5b4 \uac15\uc81c \uc885\ub8cc\uc2dc\ud0a8\ub2e4. \ub530\ub77c\uc11c \uc774\ub807\uac8c `SIGKILL` \ub85c \uc778\ud574 \uc885\ub8cc\ub41c Pod\ub294 Graceful \ud558\uac8c \uc885\ub8cc\ub418\uc9c0 \ubabb\ud558\uae30 \ub54c\ubb38\uc5d0 \ub9ac\uc18c\uc2a4\uac00 \ub0ad\ube44\ub418\uac70\ub098 HTTP Connection\uc774 \ub04a\uc5b4\uc838 502 Error\ub85c \uc774\uc5b4\uc9c8 \uc218 \uc788\ub2e4.\\n\\n\uc774\ub97c \ubc29\uc9c0\ud558\uae30 \uc704\ud574 Pod\ub294 2\uac00\uc9c0 \uc635\uc158\uc744 \ud1b5\ud574 Graceful Shutdown\uc744 \uc9c0\uc6d0\ud55c\ub2e4.\\n\\n1.  **terminationGracePeriodSeconds:** `terminationGracePeriodSeconds`\uc740 Pod\ub97c \uc548\uc804\ud558\uac8c \uc885\ub8cc\uc2dc\ud0a4\uae30 \uc704\ud55c \uc124\uc815 \uac12\uc73c\ub85c kubelet\uc774 `SIGTERM` \uc2dc\uadf8\ub110\uc744 \ubcf4\ub0b8 \ud6c4\ubd80\ud130 **\uc644\uc804\ud788 \uc885\ub8cc\ub420 \ub54c\uae4c\uc9c0 \uae30\ub2e4\ub9ac\ub294 \uc2dc\uac04(\ucd08)\uc774\ub2e4.**\\n    \uc774 \uc2dc\uac04 \ub3d9\uc548 Pod\ub294 \ud558\ub358 \uc77c\uc744 \ub9c8\ubb34\ub9ac\ud558\uace0 \uc815\uc0c1\uc801\uc73c\ub85c \ud504\ub85c\uc138\uc2a4 \uc790\uc6d0\ub4e4\uc744 \ubc18\ub0a9\ud55c \ud6c4 \uc885\ub8cc\ub41c\ub2e4.\\n2.  **preStop:** `preStop`\uc740 Kubernetes\uc5d0\uc11c \uc81c\uacf5\ud558\ub294 Lifecycle hook \uc911 \ud558\ub098\ub85c, pod\uac00 \uc885\ub8cc\ub418\uae30 \uc804\uc5d0 \uc2e4\ud589\ub418\ub294 Hook\uc774\ub2e4. `preStop`\uc740 `terminationGracePeriodSeconds` \uac12\uc774 \uc124\uc815\ub41c \uc2dc\uac04 \ub0b4\uc5d0 \uc2e4\ud589\uc744 \uc644\ub8cc\ud574\uc57c \ud558\uba70, Pod\uac00 \uc885\ub8cc\ub418\uae30 \uc804 \ub9c8\uc9c0\ub9c9 \uc791\uc5c5\uc744 \ucc98\ub9ac\ud558\ub3c4\ub85d \ud574\uc900\ub2e4.\\n    Pod\uc774 \uc885\ub8cc\ub420 \ub54c \uc885\ub8cc \uc804\uc5d0 DB \uc5f0\uacb0\uc744 \uc885\ub8cc\ud558\uace0 \ud2b8\ub79c\uc7ad\uc158\uc744 Commit\ud558\uace0 \uc885\ub8cc\ud574\uc57c \ud558\uac70\ub098 File System (FS)\uc744 \uc815\ub9ac\ud558\uace0 \uc885\ub8cc\ud574\uc57c \ud558\ub294 \uc0c1\ud669 \ub4f1\uc774 \uc788\uc744 \uc218 \uc788\ub2e4. \\n    \\n    \uc774 \ub54c `terminationGracePeriodSeconds` \ub9cc\uc73c\ub85c\ub294 Graceful \ud55c \uc885\ub8cc\ub97c \ubcf4\uc7a5\ud560 \uc218 \uc5c6\ub294\ub370 \uc774\ub97c \uc704\ud574 **`preStop`\uc774\ub780 \uac83\uc774 \uc874\uc7ac\ud55c\ub2e4.**\\n\\n---\\n\\n##  Fyi) Springboot\uc5d0\uc11c GracefulDown\\n\\n\\n> Application\uc5d0\uc11c graceful \uc124\uc815\uc744 \ucd94\uac00\ud558\uace0 preStop\uc5d0 sleep \uc124\uc815\ud558\ub294 \uac83\uc73c\ub85c \ub2ec\uc131\ud560 \uc218 \uc788\ub2e4. \ucd94\uac00\ub85c preStop Hook\uc744 \ud1b5\ud574 Kubernetes\uc758 \ub124\ud2b8\uc6cc\ud06c \ub9ac\uc18c\uc2a4\ub97c \uc815\ub9ac\ud558\ub294 \uc2dc\uac04\uc744 \ubc8c\uc5b4 \uc885\ub8cc\ub418\ub294 Pod\uc5d0 \ud2b8\ub798\ud53d\uc744 \uc804\ub2ec\ud558\uc9c0 \uc54a\ub3c4\ub85d \ud560 \uc218 \uc788\ub2e4.\\n\\n```yaml\\n---\\n# application.yml or application.properties\\nserver:\\n  shutdown: graceful # \uc2a4\ud504\ub9c1 \ubd80\ud2b8 \uc790\uccb4\uc758 Graceful Shutdown \ud65c\uc131\ud654\\n\\nspring:\\n  lifecycle:\\n    timeout-per-shutdown-phase: 10s # \uac01 \uc885\ub8cc \ub2e8\uacc4\ubcc4 \ud0c0\uc784\uc544\uc6c3 (\uae30\ubcf8\uac12 30\ucd08)\\n```\\n\\nSpring Context\ub294 \uc885\ub8cc \uc2dc\uc810\uc5d0 \uc0ac\uc6a9\ud558\ub358 bean\ub4e4\uc744 \uc815\ub9ac\ud558\ub294 \ub4f1\uc758 Context\ub97c \uc815\ub9ac\ud558\ub294 \ucf54\ub4dc\ub97c shutdown-hook\uc73c\ub85c \ucd94\uac00\ud55c\ub2e4.\\n\\n```yaml\\n---\\napiVersion: v1\\nkind: Pod\\nmetadata:\\n  name: springboot\\nspec:\\n  containers:\\n  - name: springboot\\n    image: my-springboot\\n    lifecycle:\\n      preStop:\\n        exec:\\n          command:\\n            - \\"sh\\"\\n            - \\"-c\\"\\n            # SIGTERM\uc744 \ubc1b\uc740 Pod\uac00 \uc11c\ube44\uc2a4\uc5d0\uc11c \uc548\uc804\ud558\uac8c \uc81c\uc678\ub420 \uc2dc\uac04\uc744 \ud655\ubcf4\ud569\ub2c8\ub2e4.\\n            # Endpoints Controller\uac00 Pod IP\ub97c \uc81c\uac70\ud558\uace0,\\n            # API Server\uc5d0 \ubc18\uc601\ub418\uc5b4 kube-proxy\uac00 iptables \uc815\ubcf4\ub97c \ubcc0\uacbd\ud558\ub294 \ub4f1\uc758\\n            # \ub124\ud2b8\uc6cc\ud06c \ub9ac\uc18c\uc2a4 \uc815\ub9ac \uc2dc\uac04\uc744 \ubc8c\uc5b4\uc90d\ub2c8\ub2e4.\\n            # \uc774 \uc2dc\uac04 \ub3d9\uc548 \uc0c8\ub85c\uc6b4 \uc694\uccad\uc774 \ub4e4\uc5b4\uc624\ub294 \uac83\uc744 \ubc29\uc9c0\ud558\uace0,\\n            # \uc560\ud50c\ub9ac\ucf00\uc774\uc158\uc740 \uae30\uc874 \uc694\uccad\uc744 \uc548\uc804\ud558\uac8c \ub9c8\ubb34\ub9ac\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n            - \\"sleep 30\\"\\n  # Pod\uac00 SIGTERM\uc744 \ubc1b\uace0 preStop Hook \uc2e4\ud589 \ud6c4,\\n  # \uc560\ud50c\ub9ac\ucf00\uc774\uc158\uc774 \uc644\uc804\ud788 \uc885\ub8cc\ub420 \ub54c\uae4c\uc9c0 \uae30\ub2e4\ub9ac\ub294 \uc804\uccb4 \uc2dc\uac04\uc785\ub2c8\ub2e4.\\n  # spring.lifecycle.timeout-per-shutdown-phase \ubcf4\ub2e4 \ud06c\uac70\ub098 \uac19\uc544\uc57c \ud569\ub2c8\ub2e4.\\n  terminationGracePeriodSeconds: 45\\n```\\n\\n`preStop`\uc5d0 `sleep`\uc774 \ud544\uc694\ud55c \uc8fc\ub41c \uc774\uc720\ub294 SIGTERM\uc744 \ubc1b\uc740 Pod\uac00 \uc11c\ube44\uc2a4\uc5d0\uc11c \uc548\uc804\ud558\uac8c \uc81c\uc678\ub420 \uc2dc\uac04\uc744 \ud655\ubcf4\ud558\uae30 \uc704\ud568\uc774\ub2e4. Pod\uac00 \uc885\ub8cc \uc2e0\ud638\ub97c \ubc1b\uc73c\uba74 Kubernetes\ub294 \ud574\ub2f9 Pod\ub97c \uc11c\ube44\uc2a4 \uc5d4\ub4dc\ud3ec\uc778\ud2b8 \ubaa9\ub85d\uc5d0\uc11c \uc81c\uac70\ud558\uae30 \uc2dc\uc791\ud55c\ub2e4. \uadf8\ub7ec\ub098 \uc774 \ubcc0\uacbd \uc0ac\ud56d\uc774 \ud074\ub7ec\uc2a4\ud130 \uc804\uccb4(\uc608: kube-proxy\ub97c \ud1b5\ud574 \uac01 \ub178\ub4dc\uc758 iptables \uaddc\uce59 \uc5c5\ub370\uc774\ud2b8, \ub85c\ub4dc\ubc38\ub7f0\uc11c \uc124\uc815 \ubcc0\uacbd \ub4f1)\uc5d0 \uc804\ud30c\ub418\ub294 \ub370\ub294 \uc57d\uac04\uc758 \uc2dc\uac04\uc774 \uc18c\uc694\ub420 \uc218 \uc788\ub2e4. \\n\\n`preStop` hook\uc5d0\uc11c `sleep`\uc744 \uc2e4\ud589\ud558\uba74, \uc774 \uc804\ud30c \uc2dc\uac04 \ub3d9\uc548 \uc0c8\ub85c\uc6b4 \uc694\uccad\uc774 \uc885\ub8cc \uc911\uc778 Pod\ub85c \uc804\ub2ec\ub418\ub294 \uac83\uc744 \ubc29\uc9c0\ud558\uace0, \uc560\ud50c\ub9ac\ucf00\uc774\uc158\uc774 \ud604\uc7ac \ucc98\ub9ac \uc911\uc778 \uc694\uccad\uc744 \uc644\ub8cc\ud558\uace0 \uc790\uc6d0\uc744 \uc815\ub9ac\ud560 \ucda9\ubd84\ud55c \uc2dc\uac04\uc744 \uac00\uc9c8 \uc218 \uc788\ub3c4\ub85d \ud55c\ub2e4.\\n\\n---\\n\\n### \ucd9c\ucc98\\n\\n-   https://wlsdn3004.tistory.com/14\\n-   https://yang1s.tistory.com/33"}]}}')}}]);